import type { ExamQuestion } from "./types";

export const rnPathoCatQuestions: ExamQuestion[] = [
  // ============================================================
  // DIABETES TYPE 1 & TYPE 2 CAT (40 questions)
  // ============================================================
  { q: "The charge nurse is receiving shift report on four patients. Which patient should be assessed FIRST?", o: ["A T1DM patient with blood glucose of 210 mg/dL and HbA1c of 8.2%", "A T1DM patient who is diaphoretic, confused, and tremulous with blood glucose of 38 mg/dL", "A T2DM patient requesting a dietary consult", "A T2DM patient with a blood glucose of 180 mg/dL before lunch"], a: 1, r: "Severe hypoglycemia (BG 38 mg/dL) with altered mental status is immediately life-threatening — it can progress to seizures, coma, and death within minutes. The other patients have stable, non-emergent conditions. Administer glucagon or IV dextrose immediately.", s: "Endocrine" },
  { q: "A nurse is caring for four patients. Which finding requires the MOST immediate intervention?", o: ["T2DM patient with fasting glucose of 148 mg/dL", "T1DM patient reporting numbness in both feet", "T1DM patient with blood glucose of 380 mg/dL, nausea, and Kussmaul respirations", "T2DM patient with HbA1c of 7.8%"], a: 2, r: "Blood glucose 380, nausea, and Kussmaul respirations (deep, rapid breathing compensating for metabolic acidosis) indicate evolving DKA — a life-threatening emergency. The other findings are concerning but not immediately life-threatening.", s: "Endocrine" },
  { q: "The RN is delegating tasks for four diabetic patients. Which task is appropriate to delegate to the UAP?", o: ["Teaching a newly diagnosed T1DM patient about insulin injection technique", "Performing a bedside blood glucose check on a stable T2DM patient", "Adjusting the insulin drip rate based on the sliding scale", "Assessing a patient's feet for signs of peripheral neuropathy"], a: 1, r: "A UAP can perform routine blood glucose monitoring on a stable patient. Teaching (RN scope), insulin drip adjustment (RN scope), and assessment (RN scope) cannot be delegated. The UAP should report the result to the RN for clinical interpretation.", s: "Endocrine" },
  { q: "Four patients present to the ED. Which patient needs to be seen FIRST?", o: ["Patient with T2DM, blood glucose 250, and mild headache", "Patient with T1DM, blood glucose 520, fruity breath, and confusion", "Patient with T2DM requesting a medication refill", "Patient with T1DM and HbA1c of 8.5% for routine follow-up"], a: 1, r: "Blood glucose 520, fruity breath (acetone from ketogenesis), and confusion indicate DKA with altered mental status — an immediately life-threatening emergency requiring IV fluids, insulin, and close monitoring. The other patients have non-emergent needs.", s: "Endocrine" },
  { q: "A nurse reviews morning labs for four patients. Which result requires IMMEDIATE notification of the provider?", o: ["T2DM patient with fasting glucose 132 mg/dL", "T1DM patient on an insulin drip with potassium 2.7 mEq/L", "T2DM patient with HbA1c 7.2%", "T1DM patient with fasting glucose 95 mg/dL"], a: 1, r: "Potassium 2.7 mEq/L in a patient on an insulin drip is critically dangerous. Insulin drives potassium intracellularly — the already-low K+ will drop further, risking fatal ventricular fibrillation. The insulin drip must be STOPPED and K+ replaced before resuming.", s: "Endocrine" },
  { q: "The nurse is prioritizing care for four diabetic patients. Which patient should be seen FIRST?", o: ["T2DM patient reporting blurred vision for the past week", "T1DM patient with blood glucose 65 mg/dL who feels 'fine'", "T2DM patient with a non-healing foot ulcer for 3 weeks", "T1DM patient with a hemoglobin of 10.2 g/dL"], a: 1, r: "Blood glucose 65 mg/dL is below normal (70 mg/dL) and the patient may not feel symptoms (hypoglycemia unawareness). This can rapidly progress to severe hypoglycemia with seizures and loss of consciousness. Treat with 15g fast-acting carbohydrate before it worsens.", s: "Endocrine" },
  { q: "A home health nurse is visiting four patients. Which situation requires IMMEDIATE intervention?", o: ["T2DM patient with blood glucose 190 mg/dL 2 hours after lunch", "T1DM patient who ran out of insulin 2 days ago and now has nausea and abdominal pain", "T2DM patient who missed one dose of metformin yesterday", "T1DM patient with an HbA1c of 7.5%"], a: 1, r: "A T1DM patient without insulin for 2 days is at high risk for DKA. Nausea and abdominal pain are early DKA symptoms. This patient needs immediate blood glucose and ketone testing, insulin administration, and likely emergency department evaluation.", s: "Endocrine" },
  { q: "Four patients are admitted to the medical-surgical unit. Which nursing action takes priority?", o: ["Scheduling a diabetic education class for a newly diagnosed T2DM patient", "Administering scheduled insulin lispro to a T1DM patient whose meal tray just arrived", "Documenting the morning assessment on a stable T2DM patient", "Requesting a dietitian consultation for a T2DM patient"], a: 1, r: "Rapid-acting insulin (lispro) must be given within 15 minutes of meal onset to match the postprandial glucose rise. Delaying insulin with the meal tray present risks hyperglycemia. The other tasks are important but not time-sensitive.", s: "Endocrine" },
  { q: "The nurse is reviewing lab results for four patients on an endocrine unit. Which patient requires the MOST urgent follow-up?", o: ["Patient with T2DM: fasting glucose 145 mg/dL", "Patient with T1DM recovering from DKA: anion gap 22, blood glucose 195 mg/dL", "Patient with T2DM: HbA1c 6.8%", "Patient with T1DM: fasting glucose 110 mg/dL"], a: 1, r: "An anion gap of 22 (normal <12) indicates persistent ketone production despite glucose improvement. The insulin drip must continue (with dextrose added to IV fluids) until the anion gap closes. Stopping insulin based on glucose alone would cause ketone rebound.", s: "Endocrine" },
  { q: "A nurse is teaching four patients about diabetes medications. Which patient statement requires IMMEDIATE correction?", o: ["'I take my metformin with breakfast and dinner to reduce stomach upset'", "'I take my insulin glargine at the same time every evening'", "'I take my metformin every morning, noon, and night — one tablet with each meal' (prescribed dose is 500mg twice daily)", "'I keep my opened insulin vial at room temperature'"], a: 2, r: "The patient is taking metformin THREE times daily when prescribed TWICE daily — this is a medication overdose. Metformin overdose increases lactic acidosis risk. The nurse must correct this immediately and ensure the patient understands the correct dosing schedule.", s: "Endocrine" },
  { q: "A patient with T2DM on empagliflozin (SGLT2 inhibitor) reports nausea, vomiting, and malaise. Blood glucose is 175 mg/dL. The nurse should:", o: ["Reassure the patient — the glucose is near normal", "Check serum ketones — SGLT2 inhibitors can cause euglycemic DKA with near-normal glucose", "Administer antiemetics and continue the medication", "Increase the empagliflozin dose"], a: 1, r: "SGLT2 inhibitors can cause euglycemic DKA — ketoacidosis with near-normal blood glucose. The relatively normal glucose can delay recognition. Any SGLT2 patient with nausea/vomiting/malaise needs ketone testing regardless of glucose level.", s: "Endocrine" },
  { q: "The nurse is triaging four patients in the ED. Which patient should be seen FIRST?", o: ["T2DM patient with blood glucose 280 mg/dL and mild thirst", "T1DM patient with insulin pump malfunction reporting rapid onset of nausea and muscle cramps", "T2DM patient with blood glucose 200 mg/dL requesting medication refill", "T1DM patient with blood glucose 150 mg/dL and a question about carb counting"], a: 1, r: "Insulin pump malfunction means complete cessation of insulin delivery. T1DM patients on pumps have no long-acting depot and can develop DKA within hours. Nausea and muscle cramps suggest early DKA. This patient needs immediate assessment, glucose check, and ketone testing.", s: "Endocrine" },
  { q: "Four patients with diabetes are on the nurse's assignment. Which assessment finding should be reported to the provider FIRST?", o: ["T2DM patient with blood glucose 165 mg/dL before dinner", "T1DM patient with a 2 cm blister on the plantar surface of the foot that the patient was unaware of", "T2DM patient who forgot to take morning metformin", "T1DM patient requesting insulin pen needle replacement"], a: 1, r: "An unnoticed foot blister indicates loss of protective sensation (neuropathy). Foot ulcers in diabetes can rapidly progress to infection, osteomyelitis, and potential amputation. This requires provider notification, wound assessment, and possible vascular/infection evaluation.", s: "Endocrine" },
  { q: "A nurse is preparing to administer morning insulins to four patients. Which situation requires the nurse to HOLD the insulin and contact the provider?", o: ["Patient with blood glucose 180 mg/dL scheduled for insulin lispro with breakfast", "Patient with blood glucose 55 mg/dL scheduled for insulin glargine at 8 AM", "Patient with blood glucose 210 mg/dL scheduled for insulin aspart with breakfast", "Patient with blood glucose 145 mg/dL scheduled for NPH insulin at 8 AM"], a: 1, r: "Blood glucose 55 mg/dL is hypoglycemic. While basal insulin (glargine) should generally not be stopped, the acute hypoglycemia must be treated FIRST (15g fast-acting carb) and the provider contacted to evaluate whether the basal dose needs adjustment. The other patients have appropriate glucose levels for their scheduled insulins.", s: "Endocrine" },
  { q: "A T2DM patient is scheduled for surgery at 7 AM tomorrow. Which preoperative instruction is MOST important?", o: ["Stop all medications 1 week before surgery", "Continue basal insulin as prescribed — basal insulin prevents ketogenesis even during NPO periods; blood glucose will be monitored closely", "Take double the insulin dose the morning of surgery", "Stop all insulin and diabetes medications permanently"], a: 1, r: "Basal insulin should generally be continued preoperatively (sometimes at 50-80% of usual dose per institutional protocol). Stopping basal insulin can cause hyperglycemia or DKA. The perioperative team will manage glucose with monitoring and corrections.", s: "Endocrine" },
  { q: "The nurse receives lab results for four patients. Which result is MOST concerning?", o: ["T2DM patient: creatinine 1.0 mg/dL", "T2DM patient on metformin: lactic acid 6.2 mmol/L (normal <2.0) with complaints of nausea and malaise", "T1DM patient: HbA1c 7.0%", "T2DM patient: fasting glucose 130 mg/dL"], a: 1, r: "Lactic acid 6.2 mmol/L (normal <2.0) in a patient on metformin with symptoms suggests lactic acidosis — a rare but life-threatening complication. Metformin must be stopped immediately, and the patient needs urgent evaluation including metabolic panel, renal function, and possible hemodialysis.", s: "Endocrine" },
  { q: "A nurse is caring for a patient with T1DM and gastroparesis. The patient receives insulin lispro before meals but has frequent postprandial hypoglycemia. What modification should the nurse anticipate?", o: ["Switch to insulin glargine before meals", "Administer rapid-acting insulin AFTER meals instead of before, to better match delayed gastric emptying", "Discontinue all mealtime insulin", "Give insulin only at bedtime"], a: 1, r: "In gastroparesis, delayed gastric emptying causes delayed nutrient absorption. Giving rapid-acting insulin before meals causes it to peak before food is absorbed, causing hypoglycemia. Administering insulin after meals better matches the delayed carbohydrate absorption.", s: "Endocrine" },
  { q: "The nurse is reviewing discharge instructions with four patients. Which patient statement indicates the MOST urgent need for additional teaching?", o: ["'I will check my blood sugar before each meal'", "'I will take my insulin even when I'm sick and not eating'", "'I will rotate my insulin injection sites'", "'I will store my unopened insulin in the freezer to keep it fresh'"], a: 3, r: "Insulin must NEVER be frozen — freezing destroys the protein structure, making it ineffective. Unopened insulin should be refrigerated (36-46°F), not frozen. The patient needs immediate re-education on proper insulin storage.", s: "Endocrine" },
  { q: "Four patients call the diabetes hotline. Which caller should the nurse prioritize?", o: ["T2DM patient who forgot to take evening metformin", "T1DM patient with blood glucose 340 mg/dL and large urine ketones who is vomiting and unable to keep down fluids", "T2DM patient asking about carbohydrate counting", "T1DM patient with blood glucose 195 mg/dL asking about a correction dose"], a: 1, r: "BG 340 with large ketones and vomiting = DKA. The patient is vomiting (cannot keep down oral fluids or oral medications) and has significant ketosis. This patient needs immediate emergency department evaluation for IV fluids and insulin. Instruct to call 911 or go to the ED immediately.", s: "Endocrine" },
  { q: "A nurse is managing four patients with diabetes. Which patient needs the MOST immediate follow-up?", o: ["T2DM patient with microalbuminuria on ACE inhibitor", "T2DM patient newly started on semaglutide with mild nausea", "T1DM patient with blood glucose 72 mg/dL before lunch who reports feeling 'a little shaky'", "T2DM patient with blood glucose 160 mg/dL 2 hours postprandial"], a: 2, r: "Blood glucose 72 mg/dL with symptoms (shakiness) indicates impending hypoglycemia. While technically just above the 70 mg/dL threshold, the trend is downward and the patient is symptomatic. Immediate treatment with 15g carbohydrate prevents progression to severe hypoglycemia.", s: "Endocrine" },

  // ============================================================
  // DKA / HHS CAT (20 questions)
  // ============================================================
  { q: "The nurse receives report on four patients. Which patient should be assessed FIRST?", o: ["DKA patient with blood glucose 220 mg/dL and anion gap 10 (improving)", "DKA patient whose potassium just resulted at 2.9 mEq/L while on an insulin drip", "HHS patient receiving IV fluids with blood glucose 450 mg/dL (down from 900)", "DKA patient with pH 7.28 on continuous insulin and fluids (stable)"], a: 1, r: "Potassium 2.9 mEq/L while on an insulin drip is critically dangerous. Insulin drives K+ intracellularly — the already-low K+ will plummet further, risking fatal ventricular fibrillation. The insulin drip must be STOPPED immediately and K+ replaced before resuming.", s: "Endocrine" },
  { q: "A nurse is managing four patients in the ICU. Which patient requires the MOST immediate intervention?", o: ["DKA patient with blood glucose dropping from 450 to 120 mg/dL in 2 hours", "DKA patient with blood glucose 300 mg/dL and anion gap 20", "HHS patient with blood glucose 600 mg/dL and confusion", "DKA patient with improving pH of 7.32 on IV fluids"], a: 0, r: "A glucose drop of 330 mg/dL in 2 hours (165 mg/dL/hour) is FAR too rapid (target: 50-75/hour). This dramatically increases cerebral edema risk. The insulin rate must be decreased immediately and dextrose added to IV fluids.", s: "Endocrine" },
  { q: "Four patients present to the ED with hyperglycemia. Which patient should be triaged FIRST?", o: ["T2DM patient with blood glucose 300 mg/dL, alert, and oriented", "T1DM patient with blood glucose 480 mg/dL, Kussmaul respirations, and fruity breath", "T2DM patient with blood glucose 250 mg/dL and no symptoms", "T2DM patient with blood glucose 280 mg/dL and mild nausea"], a: 1, r: "Blood glucose 480 with Kussmaul respirations (respiratory compensation for metabolic acidosis) and fruity breath (acetone from ketogenesis) indicates active DKA — a life-threatening emergency. This patient needs immediate IV access, fluids, labs (K+, pH), and insulin drip.", s: "Endocrine" },
  { q: "A child is being treated for DKA. The nurse notes sudden onset of headache, vomiting, and bradycardia with hypertension. What is the PRIORITY action?", o: ["Administer antiemetics", "STOP IV fluids and elevate the head of bed — suspect cerebral edema; notify the provider IMMEDIATELY for IV mannitol", "Increase the insulin drip rate", "Administer acetaminophen for headache"], a: 1, r: "Headache, vomiting, bradycardia, and hypertension (Cushing triad) during DKA treatment in a child = cerebral edema — the leading cause of DKA death in children. Stop IV fluids, elevate HOB 30°, administer IV mannitol or hypertonic saline, and prepare for possible intubation.", s: "Endocrine" },
  { q: "The nurse is caring for four patients recovering from DKA. Which patient is ready to transition from IV to subcutaneous insulin?", o: ["Patient with blood glucose 190 mg/dL but anion gap still 18", "Patient with blood glucose 200 mg/dL, anion gap 10, pH 7.38, able to eat, and SQ insulin given 1 hour ago", "Patient with blood glucose 150 mg/dL but unable to tolerate oral intake", "Patient with blood glucose 250 mg/dL, anion gap 24, and persistent nausea"], a: 1, r: "All transition criteria met: anion gap closed (10), pH normalized (7.38), patient can eat, and SQ insulin has been administered with 1 hour of overlap. The IV drip can be discontinued. The other patients have either persistent ketosis, inability to eat, or incomplete resolution.", s: "Endocrine" },
  { q: "The nurse receives orders for four DKA patients. Which order should be questioned?", o: ["Start IV NS at 1 liter/hour for first hour", "Start regular insulin drip at 0.1 units/kg/hour (patient's K+ is 4.5)", "Start IV insulin drip (patient's K+ is 2.8 mEq/L)", "Add D5 to IV fluids when glucose reaches 200-250 mg/dL"], a: 2, r: "Starting insulin with K+ of 2.8 mEq/L is DANGEROUS. Insulin drives K+ intracellularly, which would further drop the critically low K+ to potentially fatal levels. The order should be questioned — potassium must be replaced to ≥3.3 mEq/L BEFORE starting insulin.", s: "Endocrine" },
  { q: "An elderly patient with T2DM presents with blood glucose 1,050 mg/dL, serum osmolality 360, pH 7.36, and profound confusion. Which intervention is the FIRST priority?", o: ["Start an insulin drip immediately", "Aggressive IV normal saline bolus — correcting the profound dehydration (estimated 8-12 liter deficit) is the first priority in HHS", "Administer IV bicarbonate", "Obtain a CT scan of the head"], a: 1, r: "This is HHS with extreme dehydration. Aggressive IV fluid resuscitation is the FIRST priority — it corrects hypovolemia, reduces glucose through hemodilution and improved renal clearance (35-70 mg/dL/hour from fluids alone), and restores end-organ perfusion. Insulin is started AFTER initial fluid resuscitation.", s: "Endocrine" },
  { q: "The nurse is reviewing DKA orders. Which nursing action is the HIGHEST priority?", o: ["Drawing a metabolic panel", "Checking potassium level BEFORE starting the insulin drip", "Documenting the admission assessment", "Placing a urinary catheter"], a: 1, r: "Potassium MUST be verified before starting insulin in DKA. If K+ <3.3, insulin is contraindicated until K+ is replaced. This is the highest-priority safety check because insulin-induced hypokalemia can cause fatal cardiac arrest.", s: "Endocrine" },
  { q: "A nurse is monitoring four DKA patients. Which finding is MOST concerning?", o: ["Patient A: blood glucose 250 mg/dL, anion gap 16, pH 7.25", "Patient B: blood glucose 200 mg/dL, anion gap 10, pH 7.35", "Patient C: blood glucose 195 mg/dL, potassium 6.9 mEq/L with peaked T waves on the cardiac monitor", "Patient D: blood glucose 300 mg/dL, anion gap 20, pH 7.22 on IV insulin"], a: 2, r: "Potassium 6.9 mEq/L with peaked T waves indicates imminent risk of lethal cardiac arrhythmia. This requires IMMEDIATE intervention: IV calcium gluconate (cardioprotection), insulin + glucose (shift K+ intracellularly), and continuous cardiac monitoring. This is more urgently life-threatening than the other findings.", s: "Endocrine" },
  { q: "A nurse is assessing four patients with hyperglycemic emergencies. Which finding best differentiates HHS from DKA?", o: ["Presence of dehydration", "Extreme hyperosmolarity (>320 mOsm/kg) with minimal ketosis and pH >7.30 in HHS", "Elevated blood glucose", "Tachycardia"], a: 1, r: "HHS: extreme hyperosmolarity (>320), glucose often >600-1000, minimal/absent ketosis, pH >7.30. DKA: ketoacidosis (pH <7.30, ketones elevated), glucose 300-800. The key difference is the ABSENCE of significant ketoacidosis in HHS — enough residual insulin prevents ketogenesis.", s: "Endocrine" },
  { q: "The nurse is caring for a patient on a DKA insulin drip. Blood glucose has decreased to 230 mg/dL but the anion gap remains 18. The resident orders to discontinue the insulin drip. What should the nurse do?", o: ["Follow the order — the glucose is nearly normal", "Question the order — the elevated anion gap indicates ongoing ketone production; stopping insulin would cause ketone rebound", "Increase the insulin drip rate", "Switch to subcutaneous insulin immediately"], a: 1, r: "The anion gap of 18 indicates ongoing ketone production. Stopping insulin based on glucose alone would cause dangerous ketone rebound and recurrent DKA. The correct action is to add D5 to IV fluids and continue the insulin drip until the anion gap closes.", s: "Endocrine" },
  { q: "A patient with DKA is receiving treatment. The nurse notes the cardiac monitor shows peaked T waves. What electrolyte abnormality is most likely?", o: ["Hyponatremia", "Hyperkalemia", "Hypocalcemia", "Hypomagnesemia"], a: 1, r: "Peaked T waves are the earliest and most characteristic ECG finding of hyperkalemia. In DKA, potassium shifts extracellularly due to acidosis and insulin deficiency. As treatment progresses and K+ shifts intracellularly, the opposite (flat T waves, U waves) may develop with hypokalemia.", s: "Endocrine" },

  // ============================================================
  // THYROID DISEASE CAT (20 questions)
  // ============================================================
  { q: "The nurse receives report on four patients. Which patient should be assessed FIRST?", o: ["Patient with Graves disease: HR 98, BP 130/80, slight hand tremor", "Patient 2 hours post-thyroidectomy: temperature 105°F, HR 170, agitation, and confusion", "Patient with hypothyroidism: fatigue, constipation, TSH 12", "Patient with thyroid nodule awaiting biopsy results"], a: 1, r: "Post-thyroidectomy with hyperpyrexia (105°F), tachycardia (170), and altered mental status = thyroid storm — a life-threatening emergency. This can occur when thyroid manipulation during surgery releases stored hormone into the circulation. Immediate treatment required.", s: "Endocrine" },
  { q: "Four patients are on the endocrine unit. Which patient needs the MOST immediate intervention?", o: ["Hypothyroid patient with TSH 15 and fatigue", "Post-thyroidectomy patient (4 hours ago) reporting difficulty swallowing and visible neck swelling", "Graves disease patient with HR 110 on methimazole", "Hashimoto patient with weight gain of 5 lbs over 2 months"], a: 1, r: "Post-thyroidectomy neck swelling with dysphagia suggests hematoma formation compressing the trachea and esophagus. This can progress rapidly to complete airway obstruction. Notify the surgeon IMMEDIATELY — emergency wound opening and possible tracheostomy may be needed.", s: "Endocrine" },
  { q: "A nurse is reviewing morning medications for four patients. Which medication administration should the nurse QUESTION?", o: ["Levothyroxine 100 mcg PO at 6:30 AM on empty stomach for a hypothyroid patient", "Methimazole 10 mg PO for a patient with Graves disease", "Aspirin 325 mg for fever in a patient with suspected thyroid storm", "Propranolol 60 mg PO for a patient with hyperthyroidism and HR 128"], a: 2, r: "Aspirin is CONTRAINDICATED in thyroid storm — it displaces T4 from binding proteins, increasing free (active) T4 and worsening thyrotoxicosis. Acetaminophen should be used instead for fever. The nurse should question this order and suggest an alternative.", s: "Endocrine" },
  { q: "The nurse is prioritizing care for four patients after thyroidectomy. Which patient should be seen FIRST?", o: ["Patient reporting mild incisional pain (3/10) requesting acetaminophen", "Patient reporting tingling around the mouth and numbness in fingertips", "Patient with a hoarse voice asking for a throat lozenge", "Patient requesting information about lifelong levothyroxine therapy"], a: 1, r: "Perioral tingling and fingertip numbness are early signs of HYPOCALCEMIA from parathyroid damage during surgery. This can rapidly progress to tetany, laryngospasm, and seizures. Check serum calcium immediately and have IV calcium gluconate ready.", s: "Endocrine" },
  { q: "A patient on methimazole calls the clinic reporting sore throat and fever of 102°F. Three other patients also call with concerns. Which caller should the nurse advise to seek IMMEDIATE care?", o: ["Patient on levothyroxine with constipation", "The methimazole patient with sore throat and fever — suspect agranulocytosis", "Patient with hypothyroidism asking about dietary iodine", "Patient with thyroid nodule asking about biopsy scheduling"], a: 1, r: "Sore throat + fever on methimazole = RED FLAG for agranulocytosis (potentially fatal neutropenia). This patient must go to the ED immediately for a CBC with differential. If ANC is critically low, methimazole must be discontinued and the patient may need isolation and antibiotics.", s: "Endocrine" },
  { q: "The nurse is managing a patient in thyroid storm. Medications are ordered: PTU, propranolol, hydrocortisone, and potassium iodide. In what order should they be administered?", o: ["Potassium iodide → PTU → propranolol → hydrocortisone", "PTU first → propranolol → hydrocortisone → potassium iodide 1 hour AFTER PTU", "All medications simultaneously", "Propranolol first → then all others together"], a: 1, r: "Critical sequence: (1) PTU (blocks new hormone synthesis AND T4→T3 conversion); (2) propranolol (controls tachycardia and blocks T4→T3); (3) hydrocortisone (blocks T4→T3 and addresses potential adrenal insufficiency); (4) iodide 1 HOUR after PTU (blocks release — giving before PTU provides substrate for new synthesis).", s: "Endocrine" },
  { q: "Four patients on an endocrine unit need assessment. Which patient should the nurse see FIRST?", o: ["Hashimoto patient with TSH 18 and fatigue requesting a nap", "Hypothyroid patient with temperature 93°F, HR 44, and extreme lethargy", "Graves disease patient with HR 100 on propranolol", "Post-thyroidectomy patient (day 2) with mild hoarseness"], a: 1, r: "Temperature 93°F (hypothermia), HR 44 (severe bradycardia), and extreme lethargy in a hypothyroid patient suggest myxedema coma — a life-threatening hypothyroid emergency with 30-60% mortality. Requires ICU admission, IV levothyroxine, IV hydrocortisone, and supportive care.", s: "Endocrine" },
  { q: "The nurse is delegating tasks for thyroid patients. Which task can be safely delegated to the UAP?", o: ["Assessing a post-thyroidectomy patient for signs of hypocalcemia", "Taking vital signs on a stable hypothyroid patient receiving levothyroxine", "Teaching a Graves disease patient about methimazole side effects", "Evaluating voice quality in a post-thyroidectomy patient"], a: 1, r: "Taking vital signs on a stable patient is within the UAP's scope. Assessment (hypocalcemia signs, voice quality evaluation) and teaching (medication education) require RN-level clinical judgment and cannot be delegated.", s: "Endocrine" },

  // ============================================================
  // ADRENAL / HPA AXIS CAT (20 questions)
  // ============================================================
  { q: "The nurse receives report on four patients. Which patient should be assessed FIRST?", o: ["Cushing syndrome patient with blood glucose 210 mg/dL", "Addison disease patient with BP 72/40, HR 140, vomiting, and confusion", "Patient on prednisone 10mg daily for RA with mild weight gain", "Cushing disease patient awaiting pituitary surgery tomorrow"], a: 1, r: "Addison patient with profound hypotension, tachycardia, vomiting, and confusion = adrenal crisis — immediately life-threatening. Requires IV hydrocortisone 100mg STAT and aggressive NS resuscitation. Do NOT delay treatment for diagnostic testing.", s: "Endocrine" },
  { q: "Four patients are on the medical-surgical unit. Which situation requires the MOST urgent intervention?", o: ["Cushing patient with new-onset proximal muscle weakness", "Patient on chronic prednisone (20mg/day × 1 year) who reports stopping the medication suddenly 3 days ago and now feels severely weak and dizzy", "Addison patient taking prescribed hydrocortisone with stable vital signs", "Patient recovering from bilateral adrenalectomy on appropriate hormone replacement"], a: 1, r: "Abrupt cessation of chronic prednisone after 1 year causes adrenal crisis due to HPA axis suppression and adrenal atrophy. Severe weakness and dizziness suggest hemodynamic instability. This patient needs immediate assessment, IV hydrocortisone, and provider notification.", s: "Endocrine" },
  { q: "A nurse is caring for four patients. Which patient's lab values require IMMEDIATE provider notification?", o: ["Cushing patient: blood glucose 185 mg/dL", "Addison patient: Na 128, K 5.8, blood glucose 52", "Stable patient on fludrocortisone: Na 140, K 4.0", "Cushing patient: morning cortisol 25 mcg/dL"], a: 1, r: "Na 128 (hyponatremia), K 5.8 (hyperkalemia), and glucose 52 (hypoglycemia) in an Addison patient indicate worsening adrenal insufficiency or inadequate replacement therapy. Hyperkalemia >5.5 is dangerous (cardiac arrhythmia risk). Immediate provider notification is required.", s: "Endocrine" },
  { q: "The nurse is prioritizing tasks. Which action should be completed FIRST?", o: ["Scheduling an outpatient ACTH stimulation test for a patient with suspected adrenal insufficiency", "Administering IV hydrocortisone 100mg to a patient in acute adrenal crisis with BP 60/30", "Educating a Cushing patient about dietary sodium restriction", "Reviewing home medications with a patient on chronic prednisone for discharge tomorrow"], a: 1, r: "Adrenal crisis with BP 60/30 is immediately life-threatening. IV hydrocortisone 100mg must be given STAT — every minute of delay increases the risk of cardiovascular collapse and death. All other tasks can wait.", s: "Endocrine" },
  { q: "A nurse is reviewing medication orders for four patients. Which order should be questioned?", o: ["Hydrocortisone 15mg PO in AM and 5mg PO in PM for an Addison disease patient", "Fludrocortisone 0.1mg PO daily for a patient with primary adrenal insufficiency", "Abrupt discontinuation of prednisone 40mg daily after 6 months of therapy", "Dexamethasone 1mg PO at 11 PM for overnight suppression test"], a: 2, r: "Abrupt discontinuation of prednisone 40mg daily after 6 months WILL cause adrenal crisis. Chronic corticosteroid use suppresses the HPA axis and causes adrenal atrophy. The dose must be tapered gradually over weeks to months. This order should be questioned immediately.", s: "Endocrine" },
  { q: "An Addison disease patient is scheduled for a colonoscopy under conscious sedation. What should the nurse ensure?", o: ["No medication adjustments are needed", "Stress-dose corticosteroids are ordered — moderate procedures require double to triple the usual hydrocortisone dose", "The patient should stop hydrocortisone the day before", "Only fludrocortisone needs adjustment"], a: 1, r: "Conscious sedation for a colonoscopy represents moderate physiologic stress. The patient needs stress-dose corticosteroids (double to triple the usual dose) because the suppressed adrenal glands cannot mount an adequate cortisol response to the stress of the procedure.", s: "Endocrine" },
  { q: "Four patients call the endocrine clinic. Which caller needs the MOST urgent guidance?", o: ["Cushing patient asking about their upcoming surgery date", "Addison patient with gastroenteritis who is vomiting and unable to keep oral hydrocortisone down", "Patient on prednisone taper who reports mild fatigue", "Cushing patient reporting a 2-lb weight gain over 2 weeks"], a: 1, r: "An Addison patient who is vomiting cannot absorb oral hydrocortisone. This is a medical emergency — the patient should self-administer IM hydrocortisone from their emergency kit and go to the ED for IV hydrocortisone and fluids. Vomiting + inability to take steroids = imminent adrenal crisis.", s: "Endocrine" },
  { q: "The nurse is caring for a critically ill patient in septic shock with refractory hypotension despite IV fluids and vasopressors. Random cortisol is 7 mcg/dL. The nurse should anticipate:", o: ["No additional intervention", "Empiric IV hydrocortisone 200mg/day for relative adrenal insufficiency — a cortisol of 7 during severe stress is inappropriately low", "Switching to oral steroids", "Dexamethasone suppression testing"], a: 1, r: "During severe physiologic stress, cortisol should be >25-30 mcg/dL. A level of 7 represents relative adrenal insufficiency. Guidelines recommend empiric hydrocortisone 200mg/day (50mg q6h) for septic shock not responding to fluids and vasopressors.", s: "Endocrine" },

  // ============================================================
  // LEUKEMIA CAT (40 questions)
  // ============================================================
  { q: "The nurse receives report on four hematology patients. Which patient should be assessed FIRST?", o: ["ALL patient with ANC 800 and stable vital signs", "AML patient with ANC 120, temperature 101.2°F, and rigors", "CLL patient with WBC 45,000 and no symptoms", "ALL patient in remission for routine follow-up"], a: 1, r: "Febrile neutropenia (ANC <500 + temp >100.4°F) with rigors = suspected sepsis in a severely immunocompromised patient. This is a medical emergency requiring blood cultures and empiric broad-spectrum antibiotics within 1 HOUR. Delay increases mortality significantly.", s: "Hematology" },
  { q: "Four patients on the oncology unit need assessment. Which patient requires the MOST immediate intervention?", o: ["ALL patient with mild nausea from chemotherapy", "AML patient who started chemotherapy 18 hours ago now has potassium 6.5 mEq/L and peaked T waves on telemetry", "ALL patient requesting anti-emetics", "AML patient with Hgb 9.0 g/dL and mild fatigue"], a: 1, r: "Potassium 6.5 with peaked T waves 18 hours post-chemo = tumor lysis syndrome with life-threatening hyperkalemia. This requires IMMEDIATE intervention: IV calcium gluconate (cardioprotection), insulin + glucose, bicarbonate, and possibly emergent dialysis. Can rapidly progress to cardiac arrest.", s: "Hematology" },
  { q: "The nurse is managing four leukemia patients. Which lab result requires the MOST urgent action?", o: ["ALL patient: platelet count 45,000", "AML patient: WBC 2,500 with ANC 850", "ALL patient 24 hours post-chemo: K+ 7.1, PO4 8.5, Ca2+ 6.8, uric acid 14, creatinine 2.8", "AML patient: Hgb 10.2 g/dL"], a: 2, r: "This electrolyte pattern = full-blown tumor lysis syndrome: hyperkalemia (K+ 7.1 → fatal arrhythmia), hyperphosphatemia (8.5), severe hypocalcemia (6.8 → tetany/seizures), hyperuricemia (14 → AKI), and rising creatinine (2.8 → AKI). Multiple life-threatening abnormalities requiring emergent treatment.", s: "Hematology" },
  { q: "A nurse is prioritizing care. Which patient should be seen FIRST?", o: ["AML patient with platelet count 8,000 who just developed a sudden severe headache and confusion", "ALL patient requesting pain medication for mild bone pain", "AML patient with Hgb 7.5 g/dL awaiting PRBC transfusion", "ALL patient with a question about chemotherapy schedule"], a: 0, r: "Sudden severe headache and confusion in a severely thrombocytopenic patient (platelets 8,000) suggests intracranial hemorrhage — the most lethal complication of thrombocytopenia. This is a medical emergency requiring immediate neurological assessment, stat CT head, and emergent platelet transfusion.", s: "Hematology" },
  { q: "The nurse reviews orders for four leukemia patients. Which order should be questioned?", o: ["Oral mucositis care protocol with saline rinses every 2-4 hours", "IM injection of an antiemetic for a patient with platelet count of 12,000", "Irradiated PRBCs for a severely immunocompromised AML patient", "Neutropenic diet for a patient with ANC 300"], a: 1, r: "IM injections are CONTRAINDICATED in thrombocytopenic patients (platelets <20,000). The injection can cause an intramuscular hematoma that cannot be compressed. The nurse should question this order and request IV or subcutaneous route instead.", s: "Hematology" },
  { q: "A nurse is delegating tasks for oncology patients. Which task is appropriate for the UAP?", o: ["Assessing a patient for signs of tumor lysis syndrome", "Calculating the ANC from the morning CBC", "Recording intake and output on a patient receiving TLS prophylaxis hydration", "Administering a blood transfusion to a thrombocytopenic patient"], a: 2, r: "Recording I&O is within the UAP's scope. Assessment (TLS signs), clinical calculations (ANC), and medication/blood product administration require RN-level judgment and cannot be delegated.", s: "Hematology" },
  { q: "Four patients have lab results available. Which result should the nurse act on FIRST?", o: ["AML patient: Hgb 8.0 g/dL, clinically stable", "ALL patient on induction chemo: WBC 150, ANC 20, temperature 100.8°F", "AML patient: platelet count 28,000, no bleeding", "ALL patient: uric acid 5.5 mg/dL on allopurinol"], a: 1, r: "ANC of 20 with fever 100.8°F = severe febrile neutropenia. This patient is essentially without any immune defense. Blood cultures and empiric broad-spectrum antibiotics (piperacillin-tazobactam, cefepime, or meropenem) must be started within 1 HOUR. Delay dramatically increases mortality.", s: "Hematology" },
  { q: "An APL patient on ATRA develops fever 101°F, dyspnea with SpO2 90%, bilateral crackles, and 3 kg weight gain over 3 days. The nurse should:", o: ["Administer antipyretics and continue routine care", "Recognize differentiation syndrome — administer IV dexamethasone 10mg STAT and notify the provider immediately", "Administer furosemide for fluid overload", "Stop ATRA permanently"], a: 1, r: "Fever, dyspnea, pulmonary infiltrates, and weight gain during ATRA therapy = differentiation syndrome. Treatment is IV dexamethasone 10mg q12h started IMMEDIATELY — delay can be fatal. ATRA may be continued if the patient responds to dexamethasone.", s: "Hematology" },
  { q: "The nurse is caring for an AML patient with WBC 125,000. Which assessment finding indicates the MOST concerning complication?", o: ["Mild fatigue", "Gingival bleeding from brushing teeth", "Sudden onset of severe headache, confusion, and right arm weakness", "Low-grade fever"], a: 2, r: "WBC >100,000 + sudden neurological symptoms (headache, confusion, focal weakness) = cerebral leukostasis — blast cells sludging in the cerebral microvasculature causing stroke-like symptoms. This is a medical emergency requiring emergent leukapheresis and hydroxyurea for cytoreduction.", s: "Hematology" },
  { q: "Four patients are receiving chemotherapy. Which patient should the nurse assess FIRST?", o: ["Patient receiving vincristine IV who reports tingling in the fingers (expected neuropathy)", "Patient receiving high-dose cytarabine who has developed ataxia and difficulty with speech", "Patient receiving methotrexate intrathecally who reports mild headache", "Patient receiving daunorubicin who reports mild nausea"], a: 1, r: "Ataxia and speech difficulty during high-dose cytarabine = cerebellar toxicity — a dose-limiting complication. The infusion must be STOPPED immediately and the provider notified. If cytarabine is continued, permanent cerebellar damage can result. Neurological exam before each subsequent dose.", s: "Hematology" },
  { q: "The charge nurse is making assignments for four patients. Which patient should be assigned to the MOST experienced nurse?", o: ["ALL patient in remission for routine follow-up", "Newly diagnosed APL patient starting ATRA + arsenic trioxide with active DIC", "CLL patient on oral chemotherapy at home", "ALL patient on maintenance therapy with stable labs"], a: 1, r: "Newly diagnosed APL with active DIC is the most complex and dangerous clinical situation — requiring ATRA management (risk of differentiation syndrome), DIC monitoring/treatment (transfusion support, fibrinogen monitoring), and initial chemotherapy. This patient needs the most experienced nurse.", s: "Hematology" },
  { q: "A nurse is monitoring four patients for tumor lysis syndrome 24 hours after chemotherapy initiation. Which patient is showing the EARLIEST signs of TLS?", o: ["Patient with K+ 4.0, PO4 4.0, Ca2+ 9.0, uric acid 5.0", "Patient with K+ 5.8, PO4 6.5, Ca2+ 7.8, uric acid 10.2", "Patient with K+ 4.2, PO4 3.5, Ca2+ 9.5, uric acid 4.0", "Patient with K+ 3.8, PO4 4.2, Ca2+ 9.2, uric acid 6.0"], a: 1, r: "K+ 5.8 (rising), PO4 6.5 (elevated), Ca2+ 7.8 (falling — bound by excess phosphorus), and uric acid 10.2 (elevated) = laboratory TLS. This pattern requires immediate intervention: aggressive hydration, rasburicase for uric acid, and close electrolyte monitoring q4h. Cardiac monitoring for hyperkalemia.", s: "Hematology" },
  { q: "The nurse is reviewing morning labs for four patients. Which patient needs the MOST urgent platelet transfusion?", o: ["Patient with platelets 45,000 and no bleeding", "Patient with platelets 8,000 and new-onset gum bleeding and petechiae", "Patient with platelets 22,000 and stable vitals", "Patient with platelets 35,000 scheduled for a blood draw"], a: 1, r: "Platelets 8,000 with active bleeding (gum bleeding, petechiae) = critically low platelets with ongoing hemorrhage. This patient needs immediate platelet transfusion (transfusion threshold is 10,000 for prophylaxis, but active bleeding requires immediate transfusion regardless of count).", s: "Hematology" },

  // ============================================================
  // SICKLE CELL CAT (20 questions)
  // ============================================================
  { q: "The nurse receives report on four sickle cell patients. Which patient should be assessed FIRST?", o: ["SCD patient with vaso-occlusive crisis pain rated 7/10 receiving IV hydromorphone via PCA", "SCD patient with fever 102.5°F, HR 120, and functional asplenia", "SCD patient with chronic fatigue and Hgb 7.8 g/dL (baseline 8.0)", "SCD patient requesting refill of hydroxyurea prescription"], a: 1, r: "Fever in an SCD patient with functional asplenia = medical emergency. Encapsulated bacteria (S. pneumoniae) can cause rapidly fatal sepsis within hours in asplenic patients. Blood cultures and empiric broad-spectrum antibiotics must be started IMMEDIATELY — this takes priority over pain management.", s: "Hematology" },
  { q: "Four SCD patients present to the ED. Which patient needs the MOST immediate intervention?", o: ["Patient with bilateral hand pain and Hgb 7.5 g/dL", "Patient with new-onset fever, chest pain, cough, and SpO2 88%", "Patient with pain rated 8/10 in the lower back", "Patient requesting pain medication refill"], a: 1, r: "Fever + chest pain + cough + hypoxemia = acute chest syndrome — the leading cause of death in SCD. ACS can rapidly progress to respiratory failure and ARDS. This patient needs immediate CXR, O2, blood cultures, broad-spectrum antibiotics, and potentially emergent exchange transfusion.", s: "Hematology" },
  { q: "A nurse is caring for four SCD patients. Which assessment finding requires the MOST urgent intervention?", o: ["Patient with joint pain rated 6/10", "Child with sudden left upper quadrant pain, rapidly increasing abdominal girth, and Hgb that dropped from 7.5 to 4.0 g/dL in 2 hours", "Patient with scleral icterus and indirect bilirubin 3.5 mg/dL", "Patient with priapism for 30 minutes"], a: 1, r: "Sudden LUQ pain + rapidly falling Hgb (7.5→4.0 in 2 hours) + increasing abdominal girth = splenic sequestration crisis — massive blood pooling in the spleen causing hypovolemic shock. Life-threatening emergency requiring immediate volume resuscitation and blood transfusion.", s: "Hematology" },
  { q: "The nurse is reviewing orders for four SCD patients. Which order should be QUESTIONED?", o: ["IV D5-1/2NS at 1.5x maintenance for a patient in vaso-occlusive crisis", "Cold compresses to the affected joints for pain relief", "Hydromorphone PCA for severe vaso-occlusive pain", "Hydroxyurea 500mg PO daily for sickle cell disease"], a: 1, r: "Cold compresses are CONTRAINDICATED in SCD. Cold causes vasoconstriction, slowing blood flow and increasing transit time of RBCs through capillaries, promoting more deoxygenation and HbS polymerization. WARM compresses should be used instead to promote vasodilation.", s: "Hematology" },
  { q: "A nurse is delegating tasks for SCD patients. Which task is appropriate for the UAP?", o: ["Assessing a patient's pain level and determining if a PCA dose is needed", "Monitoring SpO2 continuously and reporting readings below the patient's baseline", "Teaching a patient about hydroxyurea side effects", "Evaluating a patient's neurological status for signs of stroke"], a: 1, r: "Monitoring and reporting vital sign readings (including SpO2) is within the UAP's scope. The UAP reports findings to the RN for clinical interpretation. Assessment, teaching, and clinical evaluation require RN-level judgment.", s: "Hematology" },
  { q: "Four SCD patients need nursing attention. Which should be seen FIRST?", o: ["Patient with chronic leg ulcer being treated with wound care", "Patient with sudden onset of right-sided weakness, facial droop, and slurred speech", "Patient with vaso-occlusive crisis pain rated 9/10 on PCA", "Patient requesting discharge education about crisis prevention"], a: 1, r: "Sudden right-sided weakness, facial droop, and slurred speech = stroke. Stroke occurs in 8-11% of SCD children by age 20 due to large-vessel vasculopathy. This is a medical emergency requiring emergent CT/MRI and exchange transfusion (target HbS <30%).", s: "Hematology" },
  { q: "The nurse is reviewing lab results for four SCD patients. Which result is MOST concerning?", o: ["Hgb 7.8 g/dL (patient's baseline is 8.0)", "Reticulocyte count 0.2% (patient's baseline is 12%) with Hgb dropping from 8.0 to 5.2 g/dL", "Indirect bilirubin 2.8 mg/dL", "WBC 11,000"], a: 1, r: "Reticulocyte count near zero (0.2% vs baseline 12%) with rapidly falling Hgb = aplastic crisis from parvovirus B19 infection. The bone marrow has stopped producing red cells, and with SCD's already-shortened RBC lifespan (10-20 days), Hgb drops rapidly. Needs immediate transfusion support.", s: "Hematology" },
  { q: "A SCD patient with priapism lasting 5 hours is in the ED. Which intervention is the priority?", o: ["Apply ice packs to the area", "Establish IV access, administer fluids and analgesics, and consult urology IMMEDIATELY — priapism >4 hours risks permanent erectile dysfunction", "Advise the patient to wait — it will resolve on its own", "Administer oral antibiotics"], a: 1, r: "Priapism >4 hours in SCD is a urologic emergency. Prolonged ischemia from vaso-occlusion in the corpora cavernosa causes permanent tissue damage and erectile dysfunction. Treatment: IV hydration, analgesics, and urgent urology consultation for aspiration/irrigation and possible exchange transfusion.", s: "Hematology" },

  // ============================================================
  // THALASSEMIA CAT (10 questions)
  // ============================================================
  { q: "The nurse receives report on four hematology patients. Which patient requires the MOST immediate assessment?", o: ["Thalassemia major patient receiving routine blood transfusion with stable vital signs", "Thalassemia major patient with new-onset dyspnea, peripheral edema, and irregular heartbeat on cardiac monitor", "Thalassemia trait patient with Hgb 10.5 g/dL and no symptoms", "Iron deficiency anemia patient starting iron supplementation"], a: 1, r: "Dyspnea, peripheral edema, and irregular heartbeat in a thalassemia major patient = iron cardiomyopathy — the leading cause of death. Cardiac iron deposition causes heart failure and arrhythmias. This patient needs immediate cardiac assessment, ECHO, and intensified iron chelation.", s: "Hematology" },
  { q: "A nurse is reviewing medication orders for four patients with microcytic anemia. Which order should be QUESTIONED?", o: ["Folic acid 1mg daily for a thalassemia major patient", "Iron sulfate 325mg TID for a patient with confirmed iron deficiency anemia", "Iron sulfate 325mg TID for a patient with beta-thalassemia trait and ferritin of 450 ng/mL", "Deferasirox for a thalassemia major patient with ferritin 2,500 ng/mL"], a: 2, r: "Iron supplementation for a thalassemia patient with ferritin 450 (already elevated) is DANGEROUS. Thalassemia causes iron OVERLOAD, not deficiency, despite the microcytic anemia. Adding iron worsens organ damage. The ferritin confirms iron overload — this patient needs chelation, not iron.", s: "Hematology" },
  { q: "Four patients are receiving blood transfusions. Which patient should the nurse assess FIRST?", o: ["Patient 30 minutes into transfusion with stable vital signs", "Patient who develops fever, chills, flank pain, and dark urine 15 minutes into the transfusion", "Patient requesting a blanket because they feel cold", "Patient asking when the transfusion will be finished"], a: 1, r: "Fever, chills, flank pain, and dark urine during transfusion = acute hemolytic transfusion reaction — a medical emergency. STOP the transfusion immediately, keep the IV line open with NS, send the blood bag and a post-transfusion blood sample to the lab, and notify the provider.", s: "Hematology" },
  { q: "The nurse is reviewing labs for a thalassemia major patient. Serum ferritin is 3,500 ng/mL and cardiac MRI T2* is 9ms. What should the nurse anticipate?", o: ["Continue current chelation regimen", "Intensification of iron chelation therapy — T2* <10ms indicates HIGH RISK of cardiac events within 1 year; this is a medical emergency", "Discontinuation of chelation therapy", "No change in management"], a: 1, r: "Cardiac T2* <10ms indicates severe cardiac iron overload with high risk of heart failure or fatal arrhythmia within 1 year. Combined with ferritin 3,500 (target <1,000), this requires urgent intensification of chelation therapy — possibly IV deferoxamine 24/7 with oral deferasirox.", s: "Hematology" },
  { q: "A nurse is caring for a child with thalassemia major. The parent asks why the child needs blood transfusions every 3-4 weeks. The best explanation is:", o: ["The child's blood is the wrong type", "The child's bone marrow produces defective red blood cells that are destroyed prematurely, causing severe anemia that requires regular transfusions to maintain adequate hemoglobin", "The child has a bleeding disorder", "The transfusions will eventually cure the condition"], a: 1, r: "In thalassemia major, excess unpaired alpha chains precipitate in developing RBCs, causing their premature destruction (ineffective erythropoiesis). The few cells that survive have shortened lifespans. Regular transfusions maintain Hgb at 9-10.5 g/dL to suppress compensatory marrow expansion and support normal growth.", s: "Hematology" },

  // ============================================================
  // PANCYTOPENIA CAT (10 questions)
  // ============================================================
  { q: "The nurse receives report on four hematology patients. Which patient should be assessed FIRST?", o: ["Aplastic anemia patient with Hgb 8.5 g/dL and mild fatigue", "Pancytopenia patient with ANC 180, temperature 100.8°F, and productive cough", "MDS patient with platelet count 45,000 and no bleeding", "Aplastic anemia patient on cyclosporine with creatinine 1.2 mg/dL"], a: 1, r: "ANC 180 + fever 100.8°F = severe febrile neutropenia with respiratory symptoms (productive cough). This is a medical emergency — blood cultures and empiric broad-spectrum antibiotics within 1 HOUR. The cough may be the only sign of pneumonia, which can be rapidly fatal in this severely neutropenic patient.", s: "Hematology" },
  { q: "A nurse is caring for four patients with pancytopenia. Which finding requires the MOST immediate intervention?", o: ["Fatigue and pallor in a patient with Hgb 9.0 g/dL", "Sudden severe headache and confusion in a patient with platelets 6,000", "Mild bruising on the forearms of a patient with platelets 35,000", "Oral thrush in a patient with ANC 400"], a: 1, r: "Sudden severe headache and confusion with platelets 6,000 = potential intracranial hemorrhage — the most lethal complication of severe thrombocytopenia. This is a medical emergency requiring immediate neurological assessment, stat CT head, and emergent platelet transfusion.", s: "Hematology" },
  { q: "The nurse is delegating tasks for pancytopenic patients. Which task can be safely delegated to the UAP?", o: ["Assessing for signs of infection in a neutropenic patient", "Recording vital signs on a stable patient and reporting any temperature above 100.4°F to the RN", "Administering a platelet transfusion", "Evaluating a patient's bleeding risk"], a: 1, r: "Recording vital signs and reporting critical values is within the UAP's scope. The UAP must know to report temperature >100.4°F immediately. Assessment (infection signs, bleeding risk) and medication/transfusion administration require RN-level clinical judgment.", s: "Hematology" },
  { q: "Four pancytopenic patients have morning labs. Which patient's results require the MOST urgent action?", o: ["Patient: Hgb 10.0, ANC 1,200, platelets 65,000", "Patient: Hgb 6.8 with chest pain and dyspnea, ANC 50, platelets 5,000", "Patient: Hgb 9.5, ANC 800, platelets 45,000", "Patient: Hgb 11.0, ANC 2,000, platelets 150,000"], a: 1, r: "Hgb 6.8 with anginal symptoms (chest pain, dyspnea) = symptomatic severe anemia requiring urgent PRBC transfusion. ANC 50 = profound neutropenia at extreme infection risk. Platelets 5,000 = spontaneous hemorrhage risk. This patient has the most critically dangerous values across all three cell lines.", s: "Hematology" },
  { q: "A nurse is reviewing orders for a patient with severe aplastic anemia (ANC 200, platelets 8,000). Which order should be QUESTIONED?", o: ["Neutropenic precautions and diet", "Daily vital signs every 4 hours including temperature", "Rectal temperature measurement every shift", "Oral care with soft toothettes and saline rinses"], a: 2, r: "Rectal temperature measurement is CONTRAINDICATED in severely thrombocytopenic patients (platelets 8,000). Rectal mucosal trauma can cause uncontrollable hemorrhage. Use oral or tympanic temperature measurement instead. Also, any rectal procedure introduces infection risk in neutropenic patients.", s: "Hematology" },

  // ============================================================
  // RHEUMATOID ARTHRITIS CAT (20 questions)
  // ============================================================
  { q: "The nurse receives report on four patients. Which patient should be assessed FIRST?", o: ["RA patient with morning stiffness lasting 2 hours today (usual is 1 hour)", "RA patient on methotrexate who reports taking the medication DAILY instead of weekly for the past 2 weeks", "RA patient with mild joint swelling in bilateral wrists", "RA patient requesting occupational therapy referral"], a: 1, r: "Daily methotrexate instead of weekly = 7x overdose for 2 weeks. This can cause fatal bone marrow suppression (pancytopenia) and acute hepatotoxicity. The nurse must immediately notify the provider, obtain STAT CBC and comprehensive metabolic panel, and hold the medication.", s: "Musculoskeletal" },
  { q: "Four RA patients need nursing attention. Which situation requires the MOST urgent action?", o: ["Patient with swan-neck deformity requesting splint adjustment", "Patient on adalimumab (TNF inhibitor) with persistent fever, night sweats, and productive cough for 3 weeks", "Patient with Bouchard nodes and morning stiffness", "Patient requesting information about joint protection techniques"], a: 1, r: "Persistent fever, night sweats, and productive cough in a patient on a TNF inhibitor = HIGH suspicion for reactivated tuberculosis. TNF-alpha is critical for granuloma containment of M. tuberculosis. This patient needs immediate chest X-ray, sputum AFB cultures, and provider notification.", s: "Musculoskeletal" },
  { q: "A nurse is reviewing lab results for four RA patients on methotrexate. Which result requires IMMEDIATE provider notification?", o: ["ESR 28 mm/hr (mildly elevated)", "WBC 1,800 with ANC 600 and platelet count 42,000", "CRP 1.5 mg/dL", "Hemoglobin 12.0 g/dL"], a: 1, r: "WBC 1,800, ANC 600, and platelets 42,000 indicate methotrexate-induced bone marrow suppression (pancytopenia). ANC <1,000 puts the patient at significant infection risk. Methotrexate must be held, the provider notified immediately, and the patient monitored closely for infection and bleeding.", s: "Musculoskeletal" },
  { q: "The nurse is prioritizing care for four RA patients. Which patient should be seen FIRST?", o: ["Patient with mild joint tenderness and DAS28 score of 3.5", "Patient on methotrexate reporting severe sore throat, fever 101.5°F, and mouth sores", "Patient requesting assistance with morning ADLs", "Patient asking about the next rheumatology appointment"], a: 1, r: "Sore throat, fever, and mouth sores in a patient on methotrexate suggest possible pancytopenia (neutropenia causing infection, thrombocytopenia causing oral bleeding/sores). STAT CBC is needed. Alternatively, severe stomatitis may indicate methotrexate toxicity requiring dose adjustment or holding.", s: "Musculoskeletal" },
  { q: "An RA patient is being prepared for elective knee replacement surgery. The nurse should ensure:", o: ["Continue all RA medications unchanged", "Cervical spine flexion/extension X-rays have been obtained to evaluate for atlantoaxial subluxation before intubation", "Increase methotrexate dose preoperatively", "No special precautions are needed for RA patients"], a: 1, r: "RA can cause atlantoaxial subluxation at C1-C2 from transverse ligament destruction. During intubation, neck manipulation can compress the spinal cord if subluxation is present. Cervical spine imaging should be obtained before any surgery requiring general anesthesia in RA patients.", s: "Musculoskeletal" },
  { q: "Four RA patients are in the clinic. Which patient needs the MOST urgent referral?", o: ["Patient with stable RA on methotrexate with ESR 15", "Patient with new-onset numbness in both hands, difficulty with fine motor tasks, and neck pain radiating down both arms", "Patient with mild bilateral knee swelling", "Patient requesting a handicapped parking placard"], a: 1, r: "Bilateral hand numbness, fine motor difficulty, and radiating neck pain in an RA patient suggest cervical myelopathy from atlantoaxial subluxation — spinal cord compression at C1-C2 is a surgical emergency. Urgent neurosurgical/orthopedic referral and cervical spine MRI are needed.", s: "Musculoskeletal" },

  // ============================================================
  // OSTEOARTHRITIS CAT (20 questions)
  // ============================================================
  { q: "The nurse is triaging four patients in an orthopedic clinic. Which patient needs the MOST immediate assessment?", o: ["OA patient with chronic bilateral knee pain rated 4/10", "OA patient who has been taking acetaminophen 1,000mg every 4 hours for the past week for severe hip pain", "OA patient requesting a cane fitting", "OA patient with Heberden nodes asking about exercise"], a: 1, r: "Acetaminophen 1,000mg every 4 hours = 6,000mg/day, far exceeding the maximum safe dose (3,000-4,000mg/day). This puts the patient at serious risk for hepatotoxicity and acute liver failure. Immediate assessment, LFTs, and patient education on safe dosing are critical.", s: "Musculoskeletal" },
  { q: "Four OA patients need nursing attention. Which situation requires the MOST urgent action?", o: ["Patient with morning stiffness lasting 15 minutes", "Patient on chronic ibuprofen who reports black, tarry stools and lightheadedness", "Patient with crepitus during knee flexion", "Patient requesting a referral for physical therapy"], a: 1, r: "Black tarry stools (melena) + lightheadedness in a patient on chronic NSAIDs = GI bleeding with potential hemodynamic instability. NSAIDs inhibit COX-1 protective prostaglandins in the gastric mucosa, causing ulceration and bleeding. This requires STAT hemoglobin, vital signs, and provider notification.", s: "Musculoskeletal" },
  { q: "A nurse is reviewing pain management orders for four OA patients. Which order should be QUESTIONED?", o: ["Topical diclofenac gel to the right knee for a 72-year-old patient", "Celecoxib 200mg daily for a patient with history of CABG surgery 6 months ago", "Acetaminophen 650mg PO every 6 hours PRN for mild OA pain", "Physical therapy referral for quadriceps strengthening"], a: 1, r: "Celecoxib (and all NSAIDs) carry a BLACK BOX WARNING for cardiovascular events and are CONTRAINDICATED in patients who have had CABG surgery. The cardiovascular risk is particularly elevated in post-CABG patients. This order should be questioned immediately.", s: "Musculoskeletal" },
  { q: "The nurse is educating four OA patients. Which patient statement requires IMMEDIATE correction?", o: ["'I use a cane in my left hand for my right knee OA'", "'I apply warm compresses in the morning for stiffness'", "'I take my glucosamine supplement with breakfast'", "'I apply cold compresses to my knee before exercise to prevent pain and take 6 extra-strength Tylenol daily'"], a: 3, r: "6 extra-strength Tylenol (500mg each) = 3,000mg/day — this is at the upper limit. The critical concern is that the patient may not realize they need to monitor total daily acetaminophen from ALL sources. Also, pre-exercise cold application for OA may worsen stiffness. This requires immediate education on safe acetaminophen use.", s: "Musculoskeletal" },
  { q: "Four patients present to the ED with joint pain. Which patient should the nurse prioritize for assessment?", o: ["OA patient with chronic knee pain rated 5/10", "Patient with sudden onset of severe hot, red, swollen right knee and fever 102°F", "OA patient requesting a medication refill", "OA patient with bilateral hand stiffness"], a: 1, r: "Sudden onset of a hot, red, severely swollen joint with fever = SEPTIC ARTHRITIS until proven otherwise — a medical emergency requiring emergent joint aspiration and IV antibiotics. Untreated septic arthritis can destroy the joint within 24-48 hours and cause systemic sepsis.", s: "Musculoskeletal" },
  { q: "A nurse is prioritizing care for four OA patients. Which patient requires the MOST immediate attention?", o: ["Patient 1 day post-total knee replacement with pain rated 4/10 on current analgesic regimen", "Patient 1 day post-total hip replacement with sudden onset of severe calf pain, swelling, and warmth in the operative leg", "Patient preparing for total knee replacement surgery tomorrow", "Patient in physical therapy for post-operative knee ROM exercises"], a: 1, r: "Sudden onset calf pain, swelling, and warmth after total hip replacement = high suspicion for deep vein thrombosis (DVT). Joint replacement surgery carries significant DVT/PE risk. This requires immediate assessment, Doppler ultrasound, and anticoagulation. DVT can progress to life-threatening pulmonary embolism.", s: "Musculoskeletal" },

  // ============================================================
  // OSTEOPOROSIS CAT (20 questions)
  // ============================================================
  { q: "The nurse receives report on four patients. Which patient should be assessed FIRST?", o: ["Osteoporosis patient with T-score -2.8 taking alendronate as prescribed", "82-year-old osteoporotic patient who fell 30 minutes ago and now has severe right hip pain, shortened and externally rotated right leg, and inability to bear weight", "Osteopenia patient scheduled for follow-up DEXA scan", "Osteoporosis patient asking about calcium and vitamin D supplementation"], a: 1, r: "Severe hip pain, shortened/externally rotated leg, and inability to bear weight after a fall in an elderly osteoporotic patient = hip fracture until proven otherwise. Hip fractures carry 20-30% one-year mortality. This patient needs immediate immobilization, pain management, X-ray, and surgical consultation.", s: "Musculoskeletal" },
  { q: "Four osteoporosis patients need nursing attention. Which situation requires the MOST urgent action?", o: ["Patient on alendronate with mild GI discomfort", "Patient on denosumab whose last injection was 8 months ago (was supposed to be every 6 months) and reports new-onset severe mid-back pain", "Patient with DEXA T-score of -2.0 discussing treatment options", "Patient on calcium supplements asking about food sources of calcium"], a: 1, r: "Denosumab more than 7 months overdue + new severe back pain = possible rebound vertebral fractures from denosumab discontinuation. Abrupt cessation of denosumab causes rapid bone loss and multiple vertebral fractures. This patient needs immediate spine imaging and urgent denosumab re-dosing or bisphosphonate initiation.", s: "Musculoskeletal" },
  { q: "A nurse is reviewing medication administration for four patients. Which observation requires IMMEDIATE correction?", o: ["Patient taking alendronate on an empty stomach with water", "Patient taking alendronate with breakfast, coffee, and calcium supplement simultaneously", "Patient taking calcium 500mg with lunch", "Patient taking vitamin D 2000 IU with dinner"], a: 1, r: "Alendronate with food, coffee, and calcium = THREE administration errors simultaneously. Food reduces absorption to near zero. Coffee interferes with absorption. Calcium chelates the bisphosphonate. The patient needs immediate re-education on correct administration.", s: "Musculoskeletal" },
  { q: "The nurse is evaluating fall risk for four osteoporotic patients. Which patient is at the HIGHEST fall risk?", o: ["72-year-old taking calcium and vitamin D, ambulatory without assistance", "84-year-old on alendronate, metoprolol, lorazepam, and oxycodone, with gait unsteadiness and two bathroom falls in the past month", "65-year-old with osteopenia doing regular weight-bearing exercises", "70-year-old with T-score -2.6 on denosumab with stable gait"], a: 1, r: "Multiple high-risk factors: advanced age (84), polypharmacy with fall-risk medications (beta-blocker → orthostatic hypotension, benzodiazepine → sedation, opioid → dizziness), gait unsteadiness, and recent falls. This patient needs immediate comprehensive fall risk assessment and medication review.", s: "Musculoskeletal" },
  { q: "Four patients call the orthopedic clinic. Which caller should the nurse prioritize?", o: ["Patient asking about DEXA scan scheduling", "75-year-old osteoporotic patient reporting new sudden severe upper back pain after lifting a grocery bag, with point tenderness at T10", "Patient asking about calcium supplement brands", "Patient requesting an appointment for next month"], a: 1, r: "Sudden severe back pain with point tenderness at T10 after minimal trauma (lifting a grocery bag) in an osteoporotic patient = new vertebral compression fracture. This patient needs same-day imaging and pain management. Compression fractures can indicate severely compromised bone integrity.", s: "Musculoskeletal" },
  { q: "A nurse is reviewing discharge instructions with four osteoporosis patients. Which patient statement indicates the MOST dangerous misunderstanding?", o: ["'I will take my calcium in divided doses'", "'I stopped my denosumab injections 4 months ago because I feel fine — I don't need them anymore'", "'I do weight-bearing exercise 3 times per week'", "'I had grab bars installed in my bathroom'"], a: 1, r: "Stopping denosumab without transitioning to a bisphosphonate is EXTREMELY DANGEROUS. Rebound bone loss causes rapid vertebral fractures within 12-18 months. The patient must understand that denosumab cannot be stopped without a transition plan. Immediate provider notification and re-initiation/transition is needed.", s: "Musculoskeletal" },
  { q: "The nurse is caring for a patient admitted with a hip fracture. Which nursing action takes the HIGHEST priority?", o: ["Scheduling a DEXA scan", "Assessing neurovascular status of the affected extremity and implementing pain management", "Ordering dietary consultation", "Providing osteoporosis education materials"], a: 1, r: "Immediate priorities for hip fracture: neurovascular assessment (circulation, sensation, movement in the affected extremity), pain management (severe pain can cause tachycardia and hypertension), immobilization, and preparation for surgical repair. DEXA and education are important but not acute priorities.", s: "Musculoskeletal" },
  { q: "Four patients on an orthopedic unit need assessment. Which should be seen FIRST?", o: ["Post-hip replacement patient on postoperative day 1 with controlled pain", "Osteoporosis patient who fell from standing height and reports hearing a 'snap' — now unable to bear weight on the left leg", "Patient recovering from knee replacement doing physical therapy exercises", "Patient with osteopenia receiving discharge instructions"], a: 1, r: "A fall from standing height with an audible 'snap' and inability to bear weight in an osteoporotic patient = likely fragility fracture. This patient needs immediate assessment, immobilization, neurovascular checks, and imaging. Fragility fractures are fractures from minimal trauma that confirm clinical osteoporosis.", s: "Musculoskeletal" },
  { q: "The nurse receives report on four patients with adrenal/HPA axis disorders. Which patient should be assessed FIRST?", o: ["Patient with Addison disease taking daily hydrocortisone with stable vital signs", "Patient on chronic prednisone who had emergency appendectomy 2 hours ago without stress-dose steroids — now BP 70/40 and altered consciousness", "Patient with Cushing syndrome awaiting DEXA scan", "Patient with adrenal incidentaloma scheduled for endocrine consult"], a: 1, r: "Hypotension and altered consciousness post-surgery without stress-dose steroids = acute adrenal crisis. The suppressed HPA axis cannot produce adequate cortisol for surgical stress. This is immediately life-threatening — administer IV hydrocortisone 100mg STAT and aggressive IV fluids.", s: "Endocrine" },
  { q: "Four patients call the endocrine clinic. Which caller should the nurse prioritize?", o: ["Patient with Addison disease reporting mild fatigue", "Patient with Addison disease who ran out of hydrocortisone 3 days ago and now has nausea, vomiting, and dizziness", "Patient on thyroid medication asking about refill timing", "Patient with Cushing syndrome scheduling a follow-up"], a: 1, r: "A patient with Addison disease without hydrocortisone for 3 days with GI symptoms and dizziness = evolving adrenal crisis. Without cortisol replacement, the patient cannot maintain blood pressure or blood glucose. Instruct to take emergency IM hydrocortisone and go to the ED immediately.", s: "Endocrine" },
  { q: "The nurse is managing four patients with HPA axis disorders. Which finding requires the MOST immediate action?", o: ["Patient on prednisone 5mg daily with mild moon face", "Patient on chronic prednisone taper who developed a 102°F fever and is shaking — current prednisone dose is 2.5mg daily", "Patient with Cushing syndrome with fasting glucose 140 mg/dL", "Patient post-adrenalectomy on stable replacement doses"], a: 1, r: "A patient on a steroid taper (still potentially HPA-suppressed) with high fever needs immediate stress-dose steroids. The infection is the 'stress' that the suppressed adrenals cannot respond to. Without stress dosing, this patient may develop adrenal crisis. Increase steroid dose AND treat the fever/infection.", s: "Endocrine" },
  { q: "Four patients with thyroid storm are being managed in the ICU. Which patient's situation requires the MOST urgent intervention?", o: ["Patient whose heart rate decreased from 160 to 120 after propranolol — improving", "Patient whose temperature rose from 103°F to 106°F despite cooling measures and has new-onset atrial fibrillation with rapid ventricular response", "Patient with thyroid storm whose TSH remains suppressed — expected finding", "Patient receiving PTU with stable vital signs"], a: 1, r: "Temperature 106°F with new atrial fibrillation indicates worsening thyroid storm despite treatment. Malignant hyperthermia and cardiac arrhythmias are the primary causes of thyroid storm death. Escalate cooling measures (ice packs, cooling blanket), increase beta-blocker dose, consider cardioversion if hemodynamically unstable.", s: "Endocrine" },
  { q: "The nurse is delegating care for four endocrine patients. Which task is appropriate for the UAP?", o: ["Teaching a patient about sick-day steroid dosing", "Assessing a patient's neurological status after thyroid storm", "Obtaining vital signs on a stable Addison disease patient taking daily medications", "Adjusting an insulin drip based on glucose results"], a: 2, r: "Vital signs on a stable patient is within UAP scope. Teaching (RN scope), neurological assessment (RN scope), and insulin drip adjustment (RN scope — requires clinical judgment) cannot be delegated. The UAP should report any vital sign abnormalities to the RN for interpretation.", s: "Endocrine" },
  { q: "Four patients need nursing attention. Which patient should be seen FIRST?", o: ["Patient with Addison disease asking about dietary sodium", "Patient admitted with thyroid storm who just received Lugol's iodine BEFORE the thionamide was given", "Patient with HPA axis suppression with stable blood pressure on replacement steroids", "Patient with subclinical hypothyroidism asking about levothyroxine"], a: 1, r: "Lugol's iodine given BEFORE thionamide = potential medication error. Without prior blockade of hormone synthesis, iodine provides substrate for MORE thyroid hormone production (Jod-Basedow effect), potentially worsening thyroid storm. The nurse must notify the provider immediately and assess for worsening symptoms.", s: "Endocrine" },
  { q: "The nurse reviews labs for four patients with HPA-related conditions. Which result requires IMMEDIATE action?", o: ["Patient on hydrocortisone replacement: AM cortisol 12 mcg/dL (adequate on replacement)", "Patient on chronic prednisone: morning cortisol 1.2 mcg/dL and morning ACTH <5 pg/mL scheduled for surgery tomorrow", "Patient with Cushing syndrome: midnight cortisol 18 mcg/dL (expected finding)", "Patient on physiologic hydrocortisone: sodium 138 mEq/L (normal)"], a: 1, r: "Morning cortisol 1.2 mcg/dL with ACTH <5 = severe HPA axis suppression. This patient scheduled for surgery tomorrow MUST have stress-dose steroid orders written BEFORE the procedure. Without stress dosing, surgical stress will precipitate adrenal crisis. Notify the surgeon and anesthesiologist immediately.", s: "Endocrine" },
  { q: "The nurse is caring for four patients in the endocrine unit. Which assessment finding should be reported FIRST?", o: ["Patient with T2DM and fasting glucose 145 mg/dL", "Patient with thyroid storm whose temperature is 104°F and now develops altered consciousness and seizure-like activity", "Patient with Addison disease with stable vital signs on replacement therapy", "Patient with Cushing syndrome with mild peripheral edema"], a: 1, r: "Altered consciousness and seizure activity in thyroid storm = life-threatening neurological complication. The extreme hypermetabolic state can cause cerebral hyperthermia and seizures. This requires immediate intervention: aggressive cooling, seizure management (benzodiazepines), and escalation of thyroid storm treatment.", s: "Endocrine" },
  { q: "Four adrenal crisis patients are being managed in the ED. Which should be reassessed FIRST?", o: ["Patient who received hydrocortisone 100mg IV 30 minutes ago and BP improved from 70/40 to 95/60", "Patient who received hydrocortisone 100mg IV 60 minutes ago but BP remains 65/38 with altered consciousness despite 2L NS", "Patient with mild hypotension responding to IV fluids alone", "Patient who is stable after hydrocortisone and IV fluids, asking questions about home management"], a: 1, r: "Persistent hypotension 60 minutes after hydrocortisone AND 2L NS = treatment failure. Consider: (1) additional hydrocortisone dose; (2) vasopressors; (3) underlying precipitant not yet identified (sepsis, MI); (4) additional IV fluid boluses. This patient is at highest risk for cardiovascular collapse.", s: "Endocrine" },
  { q: "The nurse is caring for four patients. Which situation requires the MOST immediate intervention?", o: ["Patient with well-controlled Addison disease on daily hydrocortisone", "Patient who self-discontinued prednisone 40mg/day 3 days ago 'because I felt better' and now reports severe fatigue, nausea, and lightheadedness", "Patient with Cushing syndrome awaiting diagnostic workup", "Patient on low-dose prednisone 5mg daily for rheumatoid arthritis"], a: 1, r: "Abrupt discontinuation of high-dose prednisone (40mg/day) = high risk for adrenal crisis. After weeks of 40mg daily, the HPA axis is severely suppressed. The symptoms (fatigue, nausea, lightheadedness) indicate evolving adrenal insufficiency. Resume steroids immediately and plan a proper taper with the provider.", s: "Endocrine" },
  { q: "Four patients with DKA are being monitored in the ICU. Which patient's lab values are MOST concerning?", o: ["Patient A: glucose 250, K+ 4.2, anion gap 14, pH 7.30 — improving", "Patient B: glucose 180, K+ 5.8, anion gap 8, pH 7.36 — resolving", "Patient C: glucose 200, K+ 2.4, anion gap 12, pH 7.32 — on insulin drip", "Patient D: glucose 300, K+ 4.5, anion gap 18, pH 7.25 — on insulin and fluids"], a: 2, r: "K+ 2.4 mEq/L while on an insulin drip is CRITICALLY dangerous. Insulin drives K+ intracellularly — the already-severely-low K+ will drop further, risking fatal ventricular fibrillation. STOP the insulin drip IMMEDIATELY, replace K+ aggressively, place on continuous cardiac monitoring, and do not restart insulin until K+ ≥3.3.", s: "Endocrine" },
  { q: "The nurse is triaging four patients in the ED. Which should be seen FIRST?", o: ["Patient with T2DM, glucose 220, and mild polyuria", "Elderly T2DM patient with glucose 950 mg/dL, severe confusion, and BP 80/50", "Patient with T1DM requesting insulin pen refill", "Patient with T2DM and HbA1c 8.0% for routine follow-up"], a: 1, r: "Glucose 950 + confusion + hypotension = HHS (hyperosmolar hyperglycemic state) — a medical emergency with 5-20% mortality. Profound dehydration (8-12L deficit) causes hypovolemic shock. FIRST priority: aggressive IV NS (1L/hour), restore perfusion, then start insulin after initial fluid resuscitation.", s: "Endocrine" },
  { q: "A nurse is managing four DKA patients. Which order should be questioned?", o: ["D5 NS at 150 mL/hr when glucose reaches 200 mg/dL", "KCl 40 mEq in each liter of IV fluids when K+ is 3.8", "Insulin drip at 0.1 units/kg/hr when K+ is 4.2", "IV bicarbonate 50 mEq for a patient with pH 7.28 and K+ 4.0"], a: 3, r: "IV bicarbonate is generally NOT recommended for DKA unless pH <6.9. At pH 7.28, the acidosis will correct with insulin (which stops ketone production) and fluid resuscitation. Bicarbonate can worsen hypokalemia (drives K+ intracellularly), cause paradoxical CNS acidosis, and delay ketone clearance.", s: "Endocrine" },
  { q: "The nurse is reviewing discharge medications for four diabetic patients. Which prescription requires IMMEDIATE clarification?", o: ["Metformin 500mg twice daily with meals for T2DM", "Insulin glargine at bedtime for T1DM", "Metformin 1000mg twice daily for a T2DM patient with creatinine 3.8 mg/dL and GFR 22 mL/min", "Insulin lispro before meals for T1DM"], a: 2, r: "Metformin is CONTRAINDICATED with GFR <30 mL/min (increased lactic acidosis risk from impaired renal clearance). This patient (creatinine 3.8, GFR 22) has severe renal impairment. The nurse must hold the medication and notify the provider for an alternative glucose-lowering agent.", s: "Endocrine" },
  { q: "Four patients on the hematology unit need nursing attention. Which patient should be seen FIRST?", o: ["Leukemia patient with ANC of 800 who is afebrile and eating lunch", "Leukemia patient post-chemotherapy day 10 with ANC 100 and temperature 38.5°C reporting chills", "Thalassemia patient receiving scheduled blood transfusion without complications", "Sickle cell patient with pain level 4/10 on current analgesic regimen"], a: 1, r: "Febrile neutropenia (ANC <500 + temp ≥38.3°C or sustained ≥38.0°C) is a medical emergency. This patient (ANC 100, temp 38.5°C) needs immediate blood cultures and empiric broad-spectrum IV antibiotics within 60 minutes. Every hour of delay increases mortality. The other patients are stable.", s: "Hematology" },
  { q: "The nurse is caring for four hematology patients. Which finding requires the MOST urgent action?", o: ["ALL patient with platelet count 45,000 and no active bleeding", "AML patient who just started chemotherapy and develops sudden severe headache, vomiting, and bilateral vision changes — WBC was 120,000 at admission", "CML patient on imatinib with mild nausea", "Lymphoma patient with WBC 5,000 and stable vital signs"], a: 1, r: "WBC 120,000 + sudden neurological symptoms = leukostasis. Large myeloid blasts are occluding cerebral microvasculature causing stroke-like symptoms. This is a hematologic emergency requiring emergent leukapheresis and hydroxyurea for rapid WBC reduction. Delay risks irreversible cerebral infarction.", s: "Hematology" },
  { q: "Four patients are being treated for leukemia. Which patient needs the MOST immediate intervention?", o: ["ALL patient in maintenance phase with WBC 4,500", "AML patient 24 hours post-chemotherapy with potassium 6.8 mEq/L, phosphorus 8.2, uric acid 14, and creatinine rising from 1.0 to 2.8", "CLL patient with stable lymphocyte count on observation", "ALL patient with ANC 1,200 awaiting next chemotherapy cycle"], a: 1, r: "Hyperkalemia 6.8 + hyperphosphatemia + hyperuricemia + rising creatinine = tumor lysis syndrome (TLS). This is an oncologic emergency: K+ 6.8 risks fatal cardiac arrhythmia. IMMEDIATE actions: IV calcium gluconate (cardiac protection), insulin + glucose (shift K+ intracellularly), rasburicase (uric acid reduction), aggressive hydration, and cardiac monitoring.", s: "Hematology" },
  { q: "The nurse is delegating tasks for four hematology patients. Which task can be delegated to the UAP?", o: ["Assessing a neutropenic patient for subtle signs of infection", "Teaching a thalassemia patient about iron chelation therapy", "Measuring and recording intake and output on a stable sickle cell patient receiving IV hydration", "Administering a blood transfusion to a thalassemia patient"], a: 2, r: "I&O measurement on a stable patient is within UAP scope. Assessment (recognizing subtle infection signs in neutropenic patients — may lack typical inflammatory response), teaching (iron chelation adherence), and blood product administration (requires RN for verification, monitoring for reactions) all require RN scope.", s: "Hematology" },
  { q: "Four sickle cell patients present to the ED. Which should be triaged FIRST?", o: ["Patient with VOC and pain level 7/10 in the arms", "Patient with chest pain, fever 39.5°C, new bilateral pulmonary infiltrates on X-ray, and SpO2 88% on room air", "Patient with mild joint pain requesting refill of hydroxyurea", "Patient with ankle swelling after a minor injury"], a: 1, r: "Chest pain + fever + new pulmonary infiltrates + hypoxia = acute chest syndrome (ACS) — the leading cause of death in SCD. This is a medical emergency requiring immediate oxygen, antibiotics (with atypical coverage), incentive spirometry, and likely exchange transfusion. SpO2 88% indicates significant hypoxemia.", s: "Hematology" },
  { q: "The nurse reviews labs for four hematology patients. Which result requires IMMEDIATE notification of the provider?", o: ["Thalassemia patient: Hgb 9.8 g/dL (pre-transfusion target met)", "Sickle cell patient: reticulocyte count 0.2% (normal 0.5-1.5%) — patient has had fever and rash for 3 days", "ALL patient in remission: WBC 5,200 (normal)", "AML patient post-consolidation: platelet count 85,000 (recovering)"], a: 1, r: "Reticulocyte count 0.2% (near zero) in a SCD patient with fever and rash = aplastic crisis from parvovirus B19. The infected bone marrow has stopped producing RBCs. With SCD's shortened RBC lifespan (10-20 days), Hgb will drop rapidly without RBC production. This patient needs close monitoring and likely transfusion support.", s: "Hematology" },
  { q: "Four patients are receiving blood products. Which patient needs the MOST immediate assessment?", o: ["Thalassemia patient 2 hours into transfusion with stable vital signs", "Sickle cell patient 15 minutes into transfusion who develops sudden fever, chills, flank pain, and dark urine", "ALL patient post-transfusion asking for lunch", "Thalassemia patient whose transfusion completed 1 hour ago — stable"], a: 1, r: "Fever + chills + flank pain + dark urine = acute hemolytic transfusion reaction — a medical emergency from ABO incompatibility. STOP the transfusion immediately, maintain IV access with NS, send blood and urine samples to the lab, notify the blood bank and provider, monitor for DIC and renal failure.", s: "Hematology" },
  { q: "The nurse is caring for four CAR-T therapy patients. Which patient requires the MOST urgent intervention?", o: ["Patient day 3 post-infusion with mild fatigue", "Patient day 5 post-infusion with temperature 40.2°C, BP 75/45, SpO2 89%, and confusion", "Patient day 7 post-infusion with mild headache controlled with acetaminophen", "Patient day 10 post-infusion with ANC 200 on prophylactic antibiotics"], a: 1, r: "High fever + hypotension + hypoxia + confusion = severe cytokine release syndrome (CRS Grade 3-4). This is a life-threatening CAR-T complication requiring immediate tocilizumab (IL-6 receptor antagonist), corticosteroids, vasopressors, oxygen, and ICU-level monitoring. CRS can progress to multi-organ failure.", s: "Hematology" },
  { q: "Four thalassemia patients need attention. Which situation is MOST urgent?", o: ["Patient with serum ferritin 800 ng/mL on chelation therapy (controlled)", "Patient with serum ferritin 4,500 ng/mL and new-onset dyspnea, bilateral ankle edema, and cardiac T2* MRI showing 8ms", "Patient scheduled for routine transfusion next week", "Patient asking about genetic counseling for family planning"], a: 1, r: "Ferritin 4,500 + cardiac symptoms + T2* 8ms (<10ms = severe cardiac iron overload) = impending cardiac iron-overload cardiomyopathy — the leading cause of death in thalassemia. This patient needs URGENT intensified chelation (continuous IV deferoxamine + deferiprone combination), cardiology consultation, and close monitoring.", s: "Hematology" },
  { q: "The nurse is prioritizing care for four patients with pancytopenia. Which patient needs to be seen FIRST?", o: ["Patient with WBC 2,500, Hgb 9.0, platelets 90,000 — stable with mild fatigue", "Patient with ANC 50, Hgb 5.8, platelets 8,000 — reporting gum bleeding and new petechiae, temperature 38.6°C", "Patient with pancytopenia undergoing diagnostic workup — bone marrow biopsy scheduled for tomorrow", "Patient with drug-induced pancytopenia whose CBC is slowly improving after drug discontinuation"], a: 1, r: "ANC 50 (severely neutropenic) + Hgb 5.8 (severe anemia) + platelets 8,000 (severe thrombocytopenia) + active bleeding + fever = triple-threat emergency. Immediate priorities: (1) blood cultures + empiric antibiotics for febrile neutropenia; (2) platelet transfusion for active bleeding with platelets <10,000; (3) RBC transfusion for symptomatic anemia.", s: "Hematology" },
  { q: "Four hematology patients are being managed. Which assessment finding is MOST concerning?", o: ["ALL patient with bruising on both arms from recent blood draws", "AML-M3 (APL) patient who just started ATRA therapy reporting new-onset dyspnea, weight gain of 5 lbs in 24 hours, and bilateral pulmonary infiltrates", "CLL patient with stable lymphadenopathy", "Sickle cell patient with baseline Hgb 8.2 g/dL feeling well"], a: 1, r: "Dyspnea + rapid weight gain + pulmonary infiltrates on ATRA = differentiation syndrome (formerly retinoic acid syndrome). ATRA causes rapid maturation of promyelocytes, releasing cytokines that cause capillary leak, pulmonary infiltrates, and effusions. Treatment: dexamethasone 10mg IV q12h. Can be fatal if unrecognized.", s: "Hematology" },
  { q: "The nurse receives handoff on four patients. Which patient should be assessed FIRST?", o: ["Sickle cell patient on day 2 of VOC with pain 5/10 on PCA", "ALL patient post-transplant day 14 with new rash on palms and soles, elevated bilirubin, and watery diarrhea", "Thalassemia patient with ferritin 1,200 on oral chelation", "AML patient in remission with normal CBC values"], a: 1, r: "New rash + elevated bilirubin + diarrhea post-transplant = acute graft-versus-host disease (GVHD) — a serious and potentially fatal complication. Donor T cells are attacking the recipient's skin, liver, and GI tract. This requires urgent assessment, grading, and likely initiation of corticosteroid therapy.", s: "Hematology" },
  { q: "Four patients with OA are being seen in the orthopedic clinic. Which patient needs the MOST urgent referral?", o: ["Patient with mild knee OA managing well with exercise and topical NSAIDs", "Patient with severe hip OA who now reports sudden inability to bear weight with new groin pain radiating to the thigh after twisting", "Patient with hand OA requesting information about joint protection techniques", "Patient with moderate knee OA asking about viscosupplementation"], a: 1, r: "Sudden inability to bear weight with groin/thigh pain after a twisting mechanism in a patient with severe OA = possible pathologic fracture through weakened subchondral bone, or avascular necrosis progression with cortical collapse. This patient needs urgent imaging and orthopedic evaluation for possible surgical intervention.", s: "Musculoskeletal" },
  { q: "The nurse is caring for four post-operative joint replacement patients. Which finding requires the MOST immediate action?", o: ["Post-TKR patient day 1 with pain 6/10 before physical therapy", "Post-THR patient day 2 with sudden onset chest pain, dyspnea, tachycardia, and SpO2 91%", "Post-TKR patient day 2 who cannot flex knee past 60 degrees", "Post-THR patient day 1 with appropriate surgical wound drainage"], a: 1, r: "Sudden chest pain + dyspnea + tachycardia + hypoxia post-joint replacement = suspected pulmonary embolism (PE). Joint replacement surgery carries high DVT/PE risk. This is a medical emergency: administer oxygen, obtain CT pulmonary angiogram, initiate anticoagulation if confirmed, and monitor hemodynamic stability.", s: "Musculoskeletal" },
  { q: "Four OA patients are calling the nurse advice line. Which caller needs the MOST urgent guidance?", o: ["Patient asking about the difference between heat and cold therapy for OA", "Patient who has been taking ibuprofen 800mg four times daily for 3 months and now reports black, tarry stools and epigastric pain", "Patient asking about knee brace options for OA support", "Patient requesting information about aquatic therapy programs"], a: 1, r: "Black tarry stools (melena) + epigastric pain in a patient on chronic high-dose NSAIDs = GI bleeding from NSAID-induced gastric/duodenal ulcer. This is a medical emergency. Instruct the patient to stop NSAIDs immediately, go to the ED, and seek immediate medical evaluation. Chronic NSAID use is the most common cause of peptic ulcer disease.", s: "Musculoskeletal" },
  { q: "The nurse is evaluating four patients with musculoskeletal complaints. Which patient should be evaluated FIRST?", o: ["Patient with bilateral knee OA reporting usual activity-related pain", "Patient with knee OA who now has a hot, swollen, red knee joint with temperature 39°C", "Patient with hand OA and Heberden nodes", "Patient with hip OA asking about glucosamine supplements"], a: 1, r: "Hot, swollen, red joint + fever in an OA patient = possible septic arthritis superimposed on the damaged joint. OA joints are at increased risk for septic arthritis because damaged cartilage provides a surface for bacterial adhesion. This is an emergency requiring immediate joint aspiration (synovial fluid analysis) and IV antibiotics.", s: "Musculoskeletal" },
  { q: "Four patients on the medical-surgical unit need attention. Which patient should be seen FIRST?", o: ["Patient with OA taking scheduled acetaminophen with adequate pain control", "Patient with osteoporosis who fell from bed and has new-onset severe hip pain with shortened, externally rotated right leg", "Patient with OA using a cold pack on the knee as instructed", "Patient with gout in remission on allopurinol maintenance therapy"], a: 1, r: "Severe hip pain + shortened/externally rotated leg after a fall = hip fracture in an osteoporotic patient. Hip fractures carry 20-30% one-year mortality in elderly patients. Immediate actions: immobilize, neurovascular assessment, pain management, X-ray confirmation, NPO status for potential surgery, and orthopedic consultation.", s: "Musculoskeletal" },
  { q: "The charge nurse is reviewing four patients' medication records. Which finding needs IMMEDIATE clarification?", o: ["OA patient on acetaminophen 650mg q6h scheduled (2600mg/day)", "OA patient prescribed celecoxib 200mg daily AND aspirin 325mg daily AND ibuprofen 600mg TID", "Osteoporosis patient on alendronate 70mg weekly", "OA patient using diclofenac gel topically to the affected knee"], a: 1, r: "Three concurrent NSAIDs/COX-2 inhibitors (celecoxib + aspirin + ibuprofen) = extremely dangerous polypharmacy. This dramatically increases GI bleeding risk (additive COX-1 inhibition), renal toxicity, and cardiovascular events. Additionally, ibuprofen interferes with aspirin's antiplatelet effect. The nurse must contact the prescriber immediately.", s: "Musculoskeletal" },
  { q: "The nurse is prioritizing assessments on four musculoskeletal patients. Which patient needs the MOST immediate assessment?", o: ["Post-TKR patient day 3 with expected surgical site swelling", "Post-TKR patient day 1 with new-onset calf pain, warmth, and swelling in the operated leg despite receiving DVT prophylaxis", "OA patient ambulating with walker as prescribed", "Patient with chronic low back pain from spinal OA with stable symptoms"], a: 1, r: "Calf pain, warmth, and swelling post-TKR = deep vein thrombosis (DVT) despite prophylaxis. Joint replacement patients remain at high DVT/PE risk. Do NOT massage the leg. Notify the provider for urgent Doppler ultrasound. If DVT confirmed, therapeutic anticoagulation is needed. Monitor for PE signs (dyspnea, chest pain, tachycardia).", s: "Musculoskeletal" },
  { q: "Four patients with chronic conditions are being managed. Which finding requires the MOST urgent nursing response?", o: ["Sickle cell patient with usual joint pain managed with oral analgesics", "OA patient with worsening knee stiffness lasting 5 minutes in the morning", "Thalassemia patient with ferritin 2,800 who reports new-onset palpitations, dyspnea on exertion, and bilateral ankle edema", "Leukemia patient in remission with normal CBC"], a: 2, r: "Palpitations + dyspnea + edema with ferritin 2,800 = heart failure from cardiac iron overload — the leading cause of death in transfusion-dependent thalassemia. Cardiac T2* MRI likely shows severe iron loading. This patient needs urgent cardiology consultation, intensified chelation, and heart failure management.", s: "Hematology" },
  { q: "Four patients need medication reconciliation. Which situation requires IMMEDIATE provider notification?", o: ["T2DM patient on metformin and glipizide with fasting glucose 130", "OA patient on chronic celecoxib with new creatinine elevation from 1.0 to 2.4 over 2 weeks", "Osteoporosis patient on calcium and vitamin D supplements", "Sickle cell patient on folic acid supplementation"], a: 1, r: "Creatinine doubling (1.0 → 2.4) on chronic celecoxib = NSAID-induced acute kidney injury. NSAIDs inhibit prostaglandin-mediated afferent arteriolar dilation, reducing renal blood flow. This patient needs immediate NSAID discontinuation, renal function monitoring, and evaluation for alternative analgesics. Continued use risks progression to established kidney injury.", s: "Musculoskeletal" },
  { q: "The nurse receives shift report on four patients. Which patient requires priority assessment?", o: ["DKA patient with improving anion gap (was 28, now 12) and pH 7.34", "HHS patient post-fluid resuscitation with glucose 380 mg/dL (down from 1,100) and improving mental status", "T1DM patient admitted with DKA 3 days ago, now eating, on SQ insulin, glucose 180 — IV drip discontinued 18 hours ago", "T2DM patient with glucose 500, serum osmolality 380, no ketones, pH 7.38, and profound lethargy with minimal urine output despite 3L NS"], a: 3, r: "Glucose 500, osmolality 380, no ketones, pH 7.38 = HHS with profound dehydration. Despite 3L NS, the patient has minimal urine output (suggesting severe prerenal AKI from hypovolemia) and remains lethargic. This patient needs MORE aggressive fluid resuscitation, closer monitoring, and possible ICU transfer. The 8-12L deficit in HHS may require significantly more fluid.", s: "Endocrine" },
  { q: "Four patients with endocrine emergencies need the nurse's attention. Which should be seen FIRST?", o: ["Thyroid storm patient whose heart rate is 110 after propranolol (was 165) — improving", "Adrenal crisis patient who received hydrocortisone 100mg IV and BP is now 100/65 (was 65/40) — improving", "DKA patient whose glucose dropped from 500 to 150 in 90 minutes on insulin drip", "Myxedema coma patient with stable vitals on IV levothyroxine and supportive care"], a: 2, r: "Glucose drop of 350 mg/dL in 90 minutes = approximately 230 mg/dL/hour — DANGEROUSLY fast (target: 50-75/hour). This rapid osmolality change dramatically increases cerebral edema risk. IMMEDIATELY reduce insulin drip rate, add dextrose to IV fluids, and monitor neurological status closely for headache, vomiting, or altered consciousness.", s: "Endocrine" },
  { q: "The nurse is evaluating four patients for discharge readiness. Which patient statement indicates the MOST dangerous knowledge deficit?", o: ["'I will take my metformin with meals to reduce stomach upset'", "'I will rotate my insulin injection sites within the same body area'", "'I will check my blood sugar if I feel shaky or sweaty'", "'I stopped taking my hydroxyurea because my sickle cell pain has been better lately — I don't think I need it anymore'"], a: 3, r: "Discontinuing hydroxyurea because of symptom improvement is VERY dangerous. Hydroxyurea increases HbF and reduces sickling — the symptom improvement IS the drug working. Stopping it will cause HbF to drop, sickling to increase, and crises to return (potentially worse). The patient needs immediate re-education about lifelong maintenance therapy.", s: "Hematology" },
  { q: "Four patients present to the urgent care clinic. Which patient needs IMMEDIATE ED transfer?", o: ["T2DM patient with glucose 200 requesting medication adjustment", "Sickle cell patient with sudden onset right-sided weakness, slurred speech, and facial drooping", "OA patient with knee pain rated 6/10", "Thalassemia patient requesting chelation medication refill"], a: 1, r: "Sudden right-sided weakness + slurred speech + facial drooping = acute stroke in a sickle cell patient. SCD patients have a high stroke risk (11% by age 20) from progressive cerebral vasculopathy. This is a neurological emergency requiring immediate ED transfer for CT, exchange transfusion (target HbS <30%), and possible thrombolytic evaluation.", s: "Hematology" },
  { q: "The nurse is managing four patients. Which patient assessment finding is MOST concerning?", o: ["OA patient with bilateral knee crepitus — expected finding", "Addison disease patient admitted with pneumonia whose blood pressure suddenly drops to 68/38 despite IV antibiotics and fluids", "T2DM patient with glucose 185 two hours after lunch", "Osteoporosis patient with T-score -2.8 on bisphosphonate therapy"], a: 1, r: "Addison disease patient with acute illness + sudden hypotension = adrenal crisis precipitated by the physiologic stress of pneumonia. The already-compromised adrenals cannot produce adequate cortisol for the increased demand of infection. IMMEDIATE stress-dose hydrocortisone (100mg IV) plus continued sepsis management.", s: "Endocrine" },
  { q: "Four diabetic patients need nursing attention. Which patient should be assessed FIRST?", o: ["T2DM patient with fasting glucose 160 mg/dL asking about medication adjustment", "T1DM patient on insulin pump who reports headache, confusion, and is diaphoretic — glucose 38 mg/dL", "T2DM patient with HbA1c 7.8% awaiting dietitian consultation", "T1DM patient asking about carb-counting techniques"], a: 1, r: "Glucose 38 mg/dL = severe hypoglycemia (Level 2: <54 mg/dL with neuroglycopenic symptoms). Confusion and diaphoresis indicate the brain is glucose-deprived. IMMEDIATE action: if patient can swallow, give 15g fast-acting carbs; if altered consciousness worsens, give IV D50 or glucagon IM. Recheck in 15 minutes. Determine cause (insulin pump malfunction, missed meal).", s: "Endocrine" },
  { q: "The nurse is reviewing insulin orders for four patients. Which order requires IMMEDIATE clarification?", o: ["Insulin glargine 20 units SQ at bedtime", "Insulin lispro 8 units SQ 15 minutes before meals", "Insulin regular 20 units IV push STAT for glucose 200 mg/dL", "Insulin NPH 15 units SQ before breakfast"], a: 2, r: "Regular insulin 20 units IV push for glucose 200 = potentially dangerous dose for a non-DKA patient with moderate hyperglycemia. IV insulin push causes rapid glucose drop risking severe hypoglycemia. For non-emergent hyperglycemia, SQ correction doses are appropriate. IV insulin drips (not bolus pushes) are used for DKA/HHS with continuous monitoring.", s: "Endocrine" },
  { q: "Four patients with diabetes are being discharged. Which patient statement requires the MOST urgent re-education?", o: ["'I check my feet every night before bed'", "'I always carry glucose tablets in case of low blood sugar'", "'I reuse my insulin syringes until the needle gets dull — usually about a week'", "'When my blood sugar is over 300 and I feel sick, I skip my insulin because I can't eat'"], a: 3, r: "SKIPPING insulin when glucose is >300 with illness symptoms is EXTREMELY dangerous — this is exactly when DKA develops. Illness INCREASES insulin requirements. The patient should NEVER skip insulin, check ketones, increase fluid intake, and contact their provider. This misunderstanding could be fatal.", s: "Endocrine" },
  { q: "The nurse is caring for four patients with diabetic complications. Which finding requires the MOST urgent action?", o: ["Patient with diabetic retinopathy scheduled for ophthalmology follow-up", "Patient with diabetic peripheral neuropathy reporting new painless foot ulcer with surrounding erythema, warmth, and purulent drainage", "Patient with diabetic nephropathy and microalbuminuria on ACE inhibitor", "Patient with stable diabetic gastroparesis managing symptoms with diet"], a: 1, r: "Infected diabetic foot ulcer (erythema, warmth, purulent drainage) in a patient with neuropathy = high-risk limb-threatening infection. Diabetic patients have impaired immune function and PAD that impair healing and antibiotic delivery. Immediate wound culture, blood glucose optimization, IV antibiotics, vascular assessment, and possible surgical debridement.", s: "Endocrine" },
  { q: "Four patients with thyroid disorders need the nurse's attention. Which should be seen FIRST?", o: ["Hypothyroid patient with constipation and fatigue on levothyroxine", "Post-thyroidectomy patient 6 hours post-op reporting tingling around the mouth and fingertips with positive Trousseau sign", "Hyperthyroid patient with mild tremor on methimazole", "Thyroid nodule patient awaiting FNA biopsy results"], a: 1, r: "Perioral and fingertip tingling + positive Trousseau sign post-thyroidectomy = HYPOcalcemia from inadvertent parathyroid gland removal or damage. This is a surgical emergency — severe hypocalcemia can cause tetany, laryngospasm (airway obstruction), and cardiac arrhythmias. IMMEDIATELY check calcium level, administer IV calcium gluconate, and notify the surgeon.", s: "Endocrine" },
  { q: "The nurse receives report on four endocrine patients. Which patient should be assessed FIRST?", o: ["Cushing syndrome patient with glucose 180 mg/dL and moon face", "Patient with pheochromocytoma who is being prepared for surgery and just received propranolol WITHOUT prior alpha-blocker therapy — now reports severe headache and chest pressure, BP 240/140", "Patient with hypothyroidism with TSH 8.0 on dose adjustment", "Patient with hyperparathyroidism with calcium 11.2 mg/dL"], a: 1, r: "Beta-blocker WITHOUT prior alpha-blockade in pheochromocytoma = LETHAL error. Blocking β2-mediated vasodilation while leaving α1-mediated vasoconstriction unopposed causes SEVERE hypertensive crisis. BP 240/140 with headache and chest pressure = hypertensive emergency with risk of stroke, MI, or aortic dissection. STOP propranolol, give phentolamine (alpha-blocker) IV.", s: "Endocrine" },
  { q: "Four patients with Cushing syndrome are being managed. Which finding is MOST concerning?", o: ["Patient with purple striae on abdomen", "Patient with fasting glucose 230 mg/dL, new-onset polyuria, and a deep wound infection that is not healing despite antibiotics", "Patient with moon face and central obesity", "Patient with mild proximal muscle weakness"], a: 1, r: "Hyperglycemia (230) + polyuria + non-healing wound infection = triple complication of cortisol excess. Cortisol causes hyperglycemia (gluconeogenesis), immunosuppression (impaired WBC function), and impaired wound healing (collagen synthesis inhibition). The combination of uncontrolled diabetes AND wound infection unresponsive to antibiotics requires urgent cortisol reduction and aggressive wound management.", s: "Endocrine" },
  { q: "Four patients need nursing attention. Which situation requires the MOST immediate intervention?", o: ["RA patient on methotrexate with mild nausea — takes folic acid", "RA patient who just started adalimumab (TNF inhibitor) 3 weeks ago and now presents with night sweats, productive cough, weight loss, and hemoptysis", "RA patient with stable disease on sulfasalazine", "RA patient asking about joint protection techniques"], a: 1, r: "Night sweats + cough + weight loss + hemoptysis in a patient on TNF inhibitor = suspected tuberculosis reactivation. TNF-α is essential for containing Mycobacterium tuberculosis in granulomas. TNF inhibition allows latent TB to reactivate. IMMEDIATELY stop the TNF inhibitor, isolate the patient (airborne precautions), obtain sputum for AFB smear/culture, and chest X-ray.", s: "Musculoskeletal" },
  { q: "The nurse is caring for four RA patients. Which lab result requires IMMEDIATE provider notification?", o: ["Patient on methotrexate: ALT 45 (mildly elevated, was 30 last month)", "Patient on methotrexate: WBC 1,200, ANC 400, platelet count 45,000 — patient reports sore throat and temperature 38.8°C", "Patient on hydroxychloroquine: normal CBC and CMP", "Patient on prednisone taper: glucose 140 mg/dL"], a: 1, r: "WBC 1,200 + ANC 400 + platelets 45,000 + fever + sore throat = methotrexate-induced pancytopenia with febrile neutropenia. This is a medical emergency: (1) HOLD methotrexate; (2) immediate blood cultures and empiric broad-spectrum antibiotics; (3) consider leucovorin rescue (folinic acid); (4) possible growth factor support (G-CSF). Check renal function — methotrexate accumulates in renal impairment.", s: "Musculoskeletal" },
  { q: "Four patients with musculoskeletal conditions need attention. Which should be assessed FIRST?", o: ["RA patient with bilateral wrist swelling — typical for their disease", "RA patient reporting sudden onset severe neck pain, bilateral upper extremity weakness, and difficulty walking — they had stable disease but recently fell", "OA patient with knee pain rated 5/10 after physical therapy", "Osteoporosis patient with stable T-score on annual DEXA"], a: 1, r: "Sudden neck pain + bilateral upper extremity weakness + gait difficulty after a fall in RA = cervical spinal cord compression from atlantoaxial subluxation. RA erodes the C1-C2 transverse ligament, and trauma can cause acute subluxation. This is a neurological EMERGENCY — immobilize the cervical spine, obtain emergent imaging, and neurosurgery consult.", s: "Musculoskeletal" },
  { q: "The nurse is delegating tasks for four RA patients. Which task is appropriate for the UAP?", o: ["Assessing a patient's joint swelling and disease activity", "Teaching a patient about methotrexate side effects and monitoring", "Ambulating a stable RA patient with assistive device as prescribed", "Evaluating the effectiveness of a biologic DMARD"], a: 2, r: "Ambulating a stable patient with assistive device is within UAP scope — the activity plan has already been established by the RN. Assessment (joint evaluation), teaching (medication education), and evaluation of therapy effectiveness all require RN-level clinical judgment and cannot be delegated.", s: "Musculoskeletal" },
  { q: "Four patients are being seen in the rheumatology clinic. Which patient needs the MOST urgent evaluation?", o: ["RA patient with stable disease on methotrexate and adalimumab", "RA patient reporting new-onset progressive dyspnea, dry cough, and bilateral basilar crackles over the past 3 weeks — on methotrexate for 2 years", "RA patient with mild morning stiffness lasting 20 minutes", "RA patient asking about switching from oral to injectable methotrexate"], a: 1, r: "Progressive dyspnea + dry cough + bilateral crackles on methotrexate = suspected methotrexate-induced pneumonitis OR RA-associated interstitial lung disease. Both are potentially life-threatening. Immediate chest X-ray/CT, pulmonary function tests, hold methotrexate, and consider corticosteroids if pneumonitis is confirmed.", s: "Musculoskeletal" },
  { q: "The charge nurse is reviewing four patients' treatment plans. Which plan needs IMMEDIATE revision?", o: ["RA patient on methotrexate 15mg weekly with folic acid 1mg daily", "RA patient on methotrexate who is now 6 weeks pregnant — methotrexate was not stopped before conception", "RA patient on hydroxychloroquine with annual eye exams", "RA patient on prednisone 5mg daily with calcium and vitamin D supplementation"], a: 1, r: "Methotrexate is ABSOLUTELY CONTRAINDICATED in pregnancy — FDA Category X. It is a folate antagonist that causes embryotoxicity, teratogenicity (neural tube defects, limb malformations), and spontaneous abortion. Must be stopped at least 3 months before conception (both men and women). This patient needs immediate OB consultation and methotrexate discontinuation.", s: "Musculoskeletal" },
  { q: "Four patients with hematologic conditions need the nurse's attention. Which should be assessed FIRST?", o: ["Thalassemia patient with scheduled transfusion in 2 hours", "Sickle cell patient who was hit in the left side during a fall — now has rapidly increasing left upper quadrant pain, lightheadedness, and heart rate 130", "Leukemia patient in remission with normal CBC", "Pancytopenia patient with stable counts on treatment"], a: 1, r: "Left-sided trauma + rapidly increasing LUQ pain + tachycardia in SCD = splenic sequestration crisis or splenic rupture. In children with SCD, the spleen can rapidly sequester massive blood volumes causing hypovolemic shock. In adults (or those with HbSC who retain splenic function), traumatic splenic injury is also possible. Immediate IV access, fluid resuscitation, type and crossmatch, and surgical consult.", s: "Hematology" },
  { q: "Four leukemia patients are being monitored. Which patient needs the MOST immediate intervention?", o: ["ALL patient in maintenance with stable WBC of 4,500", "AML patient starting induction who develops sudden onset confusion, bilateral visual changes, and SpO2 88% — WBC at admission was 145,000", "CML patient on imatinib with complete cytogenetic response", "ALL patient day 21 post-chemotherapy with ANC 1,500 (recovering)"], a: 1, r: "WBC 145,000 + confusion + visual changes + hypoxia = leukostasis from hyperleukocytosis. Large myeloid blasts are occluding cerebral and pulmonary microvasculature. This is a hematologic emergency: (1) emergent leukapheresis; (2) hydroxyurea for rapid cytoreduction; (3) avoid RBC transfusion (increases viscosity); (4) aggressive hydration; (5) consider TLS prophylaxis.", s: "Hematology" },
  { q: "The nurse is reviewing four patients' blood bank orders. Which order requires IMMEDIATE verification?", o: ["Type and screen for a stable thalassemia patient", "Crossmatched PRBCs for a sickle cell patient — donor unit is sickle-trait POSITIVE", "FFP for a patient with DIC and INR 3.5", "Platelets for an ALL patient with count 8,000 and mucosal bleeding"], a: 1, r: "Transfusing sickle-trait positive blood to a SCD patient = transfusion failure. The donated HbAS blood will still sickle under the patient's pathologic conditions, defeating the purpose of transfusion. SCD patients MUST receive HbS-negative blood. Notify the blood bank immediately to replace with sickle-negative units.", s: "Hematology" },
  { q: "Four patients on the hematology unit need assessment. Which finding requires the MOST urgent action?", o: ["Thalassemia patient on oral deferasirox with mild GI upset", "Sickle cell patient on chronic transfusion therapy with new cardiac MRI showing T2* value of 7ms (critical threshold: <10ms)", "ALL patient in complete remission on maintenance chemotherapy", "AML patient post-consolidation with recovering counts"], a: 1, r: "Cardiac T2* 7ms (<10ms = severe cardiac iron overload) = imminent risk of cardiac iron-overload cardiomyopathy — the #1 cause of death in transfusion-dependent patients. This patient needs URGENT intensified iron chelation: continuous IV deferoxamine + oral deferiprone (combination therapy for cardiac iron removal), cardiology consultation, and echocardiogram.", s: "Hematology" },
  { q: "The nurse is triaging four ED patients. Which patient should be seen FIRST?", o: ["Pancytopenia patient with WBC 3,000 and mild fatigue", "Aplastic anemia patient with ANC 80 who reports temperature 39.2°C, rigors, and confusion for the past 2 hours", "Thalassemia patient requesting refill of chelation medication", "Sickle cell patient with chronic joint pain requesting analgesic refill"], a: 1, r: "ANC 80 + high fever + rigors + confusion = severe neutropenic sepsis — the most immediately life-threatening presentation. With no effective neutrophils, the patient has no immune defense against infection. IMMEDIATE: blood cultures from all lines and peripherally, empiric broad-spectrum IV antibiotics within 30 minutes, IV fluids, lactate level, and ICU evaluation.", s: "Hematology" },
  { q: "Four patients with pancytopenia are being managed. Which patient situation is MOST concerning?", o: ["Patient with B12 deficiency pancytopenia receiving weekly IM B12 injections — counts slowly improving", "Patient with aplastic anemia, ANC 200, who develops sudden dyspnea and pleuritic chest pain after 3 days of bedrest due to fatigue", "Patient with drug-induced pancytopenia whose counts are normalizing after drug discontinuation", "Patient with MDS on erythropoiesis-stimulating agent with stable hemoglobin"], a: 1, r: "Sudden dyspnea + pleuritic chest pain after prolonged bedrest = suspected pulmonary embolism. Pancytopenia patients are at increased VTE risk (especially with immobility) despite thrombocytopenia (the coagulation cascade can still be activated). Obtain CT pulmonary angiogram, start anticoagulation if confirmed (carefully — bleeding risk with low platelets), and monitor hemodynamics.", s: "Hematology" },
  { q: "The nurse reviews discharge teaching for four hematology patients. Which patient statement indicates the MOST dangerous misunderstanding?", o: ["Thalassemia patient: 'I take my chelation medication every day as prescribed'", "Sickle cell patient: 'I drink plenty of water especially in hot weather'", "Aplastic anemia patient: 'I take aspirin for headaches because it's just over-the-counter'", "Leukemia patient: 'I wash my hands frequently and avoid sick contacts'"], a: 2, r: "Aspirin in an aplastic anemia patient with thrombocytopenia = dangerous. Aspirin irreversibly inhibits platelet cyclooxygenase, impairing the function of the FEW platelets the patient has. This dramatically increases bleeding risk. Patients with pancytopenia must avoid aspirin, NSAIDs, and other antiplatelet agents. Use acetaminophen for pain/headache.", s: "Hematology" },
  { q: "Four patients with endocrine conditions are being monitored. Which finding requires the MOST immediate intervention?", o: ["T2DM patient with HbA1c 7.5% — above goal but stable", "T1DM patient on insulin pump who pulled out the infusion site 4 hours ago and now has glucose 450, nausea, abdominal pain, and fruity breath odor", "Hypothyroid patient with slightly elevated TSH on current levothyroxine dose", "T2DM patient with fasting glucose 145 on metformin"], a: 1, r: "Insulin pump disconnection for 4 hours + glucose 450 + nausea + abdominal pain + fruity breath = evolving DKA. Insulin pump patients have NO long-acting insulin depot — DKA can develop within 4-6 hours of pump disconnection. IMMEDIATE: check ketones, administer SQ rapid-acting insulin, restore pump or start IV insulin drip, IV fluids, and monitor electrolytes.", s: "Endocrine" },
  { q: "The nurse is caring for four patients. Which assessment finding warrants the MOST urgent intervention?", o: ["RA patient with bilateral MCP swelling — expected finding", "T1DM patient who exercised vigorously 2 hours ago and now has glucose 42, is confused, diaphoretic, and combative — refusing oral intake", "OA patient with knee crepitus during range of motion", "Thalassemia patient with ferritin 900 on chelation therapy"], a: 1, r: "Glucose 42 + confusion + combative + refusing oral = severe hypoglycemia (Level 3) requiring parenteral treatment. The patient CANNOT safely swallow. IMMEDIATE: administer glucagon 1mg IM (or intranasal) or IV dextrose 50% (D50) 25-50mL. Position on side (aspiration risk). Do NOT attempt oral glucose in a combative, confused patient — aspiration risk.", s: "Endocrine" },
  { q: "Four patients are being managed in the ED. Which patient should be seen FIRST?", o: ["Sickle cell patient with VOC and pain 7/10 — IV access established, awaiting analgesics", "T2DM patient with glucose 280 requesting medication refill", "Thalassemia patient feeling fatigued with Hgb 8.5 (baseline 9.0)", "Post-thyroidectomy patient 2 days ago with new-onset stridor, difficulty breathing, and neck swelling"], a: 3, r: "Post-thyroidectomy stridor + dyspnea + neck swelling = post-surgical hematoma causing airway compression — a LIFE-THREATENING surgical emergency. The expanding hematoma compresses the trachea, causing airway obstruction. IMMEDIATE: call the surgeon, open the neck incision at bedside to evacuate the hematoma if airway is threatened, and prepare for emergent intubation.", s: "Endocrine" },
  { q: "The charge nurse is assigning four patients. Which patient requires the MOST experienced RN?", o: ["Stable T2DM patient on oral medications for routine monitoring", "DKA patient on continuous insulin drip with potassium replacement requiring hourly glucose checks, q2h electrolytes, and continuous cardiac monitoring", "OA patient post-TKR day 3 progressing well with physical therapy", "Hypothyroid patient on stable levothyroxine dose"], a: 1, r: "DKA management requires the most experienced nurse: (1) continuous insulin drip with hourly glucose monitoring and rate adjustments; (2) critical potassium management (check before and during insulin, replace aggressively); (3) fluid balance monitoring; (4) anion gap trending; (5) transition planning (SQ insulin overlap before stopping drip); (6) continuous cardiac monitoring for dysrhythmias from electrolyte shifts.", s: "Endocrine" },
  { q: "Four hematology patients need nursing attention. Which patient should be assessed FIRST?", o: ["Sickle cell patient with baseline hemoglobin 7.8 who feels well", "Leukemia patient post-chemotherapy day 8, ANC 50, who just spiked a temperature to 38.5°C and reports severe perianal pain", "Thalassemia patient receiving a routine transfusion with stable vital signs", "Pancytopenia patient with stable counts on immunosuppressive therapy"], a: 1, r: "Severe neutropenia (ANC 50) + fever + perianal pain = neutropenic enterocolitis (typhlitis) or perianal abscess — both can be rapidly fatal in neutropenic patients. Perianal infections are especially dangerous because: (1) rectal mucosa breaks down during chemotherapy; (2) GI flora invade without neutrophil defense. IMMEDIATE: broad-spectrum antibiotics (include anaerobic coverage), NO rectal exam (perforation risk), surgical consult, and imaging.", s: "Hematology" },
  { q: "The nurse is evaluating four patients for potential complications. Which finding is MOST concerning?", o: ["SCD patient with baseline Hgb 7.5 who is asymptomatic", "SCD patient 2 days into VOC who now develops sudden chest pain, SpO2 dropping from 97% to 89%, temperature 39°C, and new right lower lobe infiltrate on X-ray", "Thalassemia patient with ferritin 1,100 on chelation", "AML patient in remission with normal CBC"], a: 1, r: "VOC patient + new chest pain + rapidly dropping SpO2 + fever + new infiltrate = acute chest syndrome (ACS) developing during hospitalization. ACS is the #1 cause of death in SCD. The VOC may have triggered pulmonary fat embolism from bone marrow infarction. IMMEDIATE: high-flow O2, blood cultures, antibiotics (cephalosporin + macrolide), exchange transfusion, and incentive spirometry.", s: "Hematology" },
  { q: "Four patients with musculoskeletal conditions need assessment. Which patient should be seen FIRST?", o: ["OA patient with moderate knee pain managed with NSAIDs and PT", "RA patient who had a biologic DMARD infusion 30 minutes ago and now has facial flushing, urticaria, throat tightness, and wheezing", "Osteoporosis patient with T-score -2.5 asking about medication options", "OA patient post-TKR day 2 doing prescribed exercises"], a: 1, r: "Facial flushing + urticaria + throat tightness + wheezing during/after biologic infusion = anaphylactic reaction. This is an IMMEDIATE life-threatening emergency. STOP the infusion, administer epinephrine 0.3mg IM (anterolateral thigh), maintain airway, give oxygen, IV fluids for hypotension, and call rapid response/code team.", s: "Musculoskeletal" },
  { q: "The nurse is caring for four patients on the orthopedic unit. Which assessment finding requires the MOST immediate action?", o: ["Post-TKR patient day 1 with expected surgical site swelling", "Post-THR patient day 1 who reports sudden severe hip pain, the operated leg appears shortened and internally rotated, and the patient cannot move it", "OA patient waiting for outpatient MRI results", "Post-TKR patient day 3 with ROM improving to 90 degrees"], a: 1, r: "Sudden severe pain + shortened/internally rotated leg post-THR = posterior hip dislocation. This is an orthopedic emergency requiring immediate closed reduction under sedation. Delay causes: (1) sciatic nerve injury from stretching; (2) avascular necrosis of the femoral head from vascular disruption; (3) increased difficulty of reduction. Notify surgeon STAT and keep patient immobilized.", s: "Musculoskeletal" },
  { q: "The nurse receives report on four patients. Which patient should be assessed FIRST?", o: ["T2DM patient on metformin with glucose 155", "OA patient on celecoxib and lisinopril whose lab results show: potassium 6.2 mEq/L, creatinine 3.1 (was 1.2 last month), and BUN 48", "RA patient with mild morning stiffness and swollen MCP joints", "Sickle cell patient with baseline pain managed with oral analgesics"], a: 1, r: "Potassium 6.2 + creatinine tripled + BUN elevated = acute kidney injury with dangerous hyperkalemia. Likely NSAID-induced (celecoxib) compounded by ACE inhibitor (lisinopril) — both reduce renal perfusion through different mechanisms. K+ 6.2 risks fatal cardiac arrhythmia. IMMEDIATE: 12-lead ECG, IV calcium gluconate for cardiac protection, stop celecoxib AND lisinopril, and notify nephrologist.", s: "Musculoskeletal" },
  { q: "Four patients with chronic conditions are being evaluated. Which patient needs the MOST urgent nursing intervention?", o: ["Osteoporosis patient on denosumab with stable DEXA results", "RA patient on rituximab who develops progressive multifocal leukoencephalopathy (PML) symptoms: new cognitive changes, visual disturbance, motor weakness, and speech difficulties", "OA patient with mild crepitus during knee flexion", "T2DM patient with controlled glucose on oral agents"], a: 1, r: "Cognitive changes + visual disturbance + motor weakness + speech difficulties on rituximab = suspected PML from JC virus reactivation. PML is a rare but often FATAL complication of B-cell depleting therapies (rituximab). The JC virus destroys oligodendrocytes, causing progressive white matter demyelination. IMMEDIATELY stop rituximab, obtain brain MRI, and neurology consult.", s: "Musculoskeletal" },
  { q: "The nurse is prioritizing four patients on the medical-surgical unit. Which patient should be seen FIRST?", o: ["DKA patient whose anion gap closed, pH 7.38, eating meals — transitioned to SQ insulin 6 hours ago", "SCD patient with VOC pain managed at 4/10 on PCA", "AML patient post-induction day 14 with expected pancytopenia, afebrile, on prophylactic antibiotics", "Thalassemia patient with new-onset rapid irregular heart rate of 158, dyspnea, and chest tightness — ferritin was 3,800 at last check"], a: 3, r: "New rapid irregular rhythm + dyspnea + chest tightness with ferritin 3,800 = cardiac iron-overload arrhythmia/cardiomyopathy. This is immediately life-threatening: iron overload damages the cardiac conduction system (arrhythmias) and myocardium (heart failure). IMMEDIATE: 12-lead ECG (likely atrial fibrillation), rate control, echocardiogram, emergent intensified chelation, and cardiology consult.", s: "Hematology" },
  { q: "Four patients need the nurse's attention. Which patient requires the MOST immediate assessment?", o: ["OA patient using prescribed topical diclofenac with good pain control", "Post-thyroidectomy patient 12 hours post-op with inspiratory stridor and increasing respiratory distress", "Stable RA patient asking about heat vs cold therapy for joint stiffness", "T2DM patient with glucose 190 requesting diabetes educator referral"], a: 1, r: "Post-thyroidectomy stridor + respiratory distress = airway emergency from either: (1) bilateral recurrent laryngeal nerve injury (vocal cord paralysis); (2) expanding neck hematoma compressing the trachea; or (3) laryngeal edema. IMMEDIATE: call rapid response, prepare for emergent intubation or surgical airway, and have the surgeon evaluate for neck hematoma evacuation.", s: "Endocrine" },
  { q: "Four patients with diabetic complications are being managed. Which patient requires the MOST immediate nursing intervention?", o: ["T2DM patient with stable peripheral neuropathy on gabapentin", "T1DM patient with proliferative diabetic retinopathy who reports sudden painless vision loss in the right eye with 'floaters and curtain-like shadow'", "T2DM patient with microalbuminuria on lisinopril", "T1DM patient with gastroparesis managing with small frequent meals"], a: 1, r: "Sudden painless vision loss + floaters + curtain-like shadow in proliferative retinopathy = vitreous hemorrhage or retinal detachment. Neovascularization creates fragile vessels that rupture, causing vitreous hemorrhage. Tractional retinal detachment can follow. This is an ophthalmologic EMERGENCY requiring immediate retina specialist evaluation — delay risks permanent vision loss.", s: "Endocrine" },
  { q: "The nurse is managing four patients on insulin therapy. Which situation is MOST dangerous?", o: ["Patient who forgot morning insulin lispro — took it 30 minutes late with lunch", "Patient who accidentally took insulin glargine 40 units instead of NPH 40 units before bed", "Patient who mixed insulin correctly and administered SQ", "Patient who had glucose 95 and ate breakfast before insulin injection"], a: 1, r: "Glargine and NPH have VERY different profiles: NPH has a peak (4-12 hours) while glargine is peakless (24 hours). If the patient took glargine thinking it was NPH, the error itself is not immediately dangerous. However, confusion between insulin types (wrong insulin, wrong dose) is a leading cause of serious medication errors. Verify the patient understands which insulin to take when.", s: "Endocrine" },
  { q: "Four patients call the diabetes nurse educator. Which caller needs the MOST urgent guidance?", o: ["T2DM patient asking about carb counting for better glucose control", "T1DM patient on insulin pump reporting glucose >500 for 3 hours, positive ketones, and pump shows 'occlusion alarm' — patient has not given any manual injections", "T2DM patient with fasting glucose 140 asking about medication timing", "T1DM patient asking about CGM sensor calibration"], a: 1, r: "Insulin pump occlusion + glucose >500 + positive ketones for 3 hours = EVOLVING DKA. Pump patients have NO long-acting insulin depot — DKA develops within 4-6 hours of insulin delivery failure. IMMEDIATE: give SQ rapid-acting insulin by SYRINGE (not the pump), check blood ketones, hydrate aggressively, change pump site, and go to ED if ketones are moderate/large or vomiting.", s: "Endocrine" },
  { q: "The nurse is caring for four patients. Which patient assessment should take HIGHEST priority?", o: ["Cushing syndrome patient on ketoconazole with fasting glucose 160", "Myxedema coma patient on day 2 of IV levothyroxine with temperature 96°F (35.6°C), HR 52, RR 10, and GCS declining from 12 to 8", "Hypothyroid patient on levothyroxine with TSH 6.5", "Hyperthyroid patient on methimazole with heart rate 88 — controlled"], a: 1, r: "GCS declining (12→8) + persistent hypothermia + bradycardia + hypoventilation in myxedema coma = inadequate treatment response or worsening. The declining GCS is most concerning — indicates cerebral hypoperfusion or hypothermic encephalopathy. IMMEDIATE: reassess thyroid hormone dosing, consider IV T3 (faster onset than T4), support ventilation, and warming measures. May need ICU transfer.", s: "Endocrine" },
  { q: "Four patients need nursing attention. Which finding requires the MOST immediate action?", o: ["T2DM patient with A1c 7.2% — slightly above target", "T1DM patient who just self-administered insulin and is now having an anaphylactic reaction — hives, lip/tongue swelling, wheezing, and BP 80/50", "Hypothyroid patient requesting thyroid medication refill", "T2DM patient with neuropathy applying capsaicin cream as directed"], a: 1, r: "Anaphylaxis to insulin (rare but can occur with any formulation, especially if prior allergy to additives like protamine in NPH) = life-threatening emergency. IMMEDIATE: epinephrine 0.3mg IM in anterolateral thigh, call code/rapid response, position flat with legs elevated, supplemental O2, IV access, and prepare for repeat epinephrine in 5-15 minutes if no improvement.", s: "Endocrine" },
  { q: "Four patients with hematologic conditions need the nurse's attention. Which should be assessed FIRST?", o: ["Thalassemia major patient on regular transfusions with ferritin 1,100 — on chelation", "SCD patient with priapism lasting 5 hours who reports severe penile pain", "ALL patient in complete remission on maintenance chemotherapy", "MDS patient with stable pancytopenia on azacitidine"], a: 1, r: "Priapism >4 hours = ischemic priapism, a urologic EMERGENCY in SCD. Vaso-occlusion of penile venous outflow causes ischemic damage to corporal smooth muscle. Without treatment within 4-6 hours, irreversible fibrosis → permanent erectile dysfunction. IMMEDIATE: urology consultation for corporal aspiration and phenylephrine irrigation, IV fluids, and consider exchange transfusion.", s: "Hematology" },
  { q: "The nurse is reviewing medications for four hematology patients. Which medication combination requires IMMEDIATE clarification?", o: ["SCD patient on hydroxyurea and folic acid", "Thalassemia patient on deferasirox and vitamin C 500mg daily", "Pancytopenia patient on cyclosporine and eltrombopag", "ALL patient on maintenance chemotherapy with TMP-SMX prophylaxis"], a: 1, r: "Vitamin C with iron chelation requires careful dosing — vitamin C MOBILIZES iron from tissue stores, and in iron-overloaded patients, this can cause a sudden increase in free iron that overwhelms chelation capacity, causing acute cardiac toxicity. Maximum vitamin C is 100-200mg daily, and ONLY while the chelator is actively working. 500mg is too high.", s: "Hematology" },
  { q: "Four patients are being monitored on the hematology unit. Which situation requires the MOST urgent nursing action?", o: ["Leukemia patient with platelet count 45,000 — no active bleeding, on fall precautions", "SCD patient with chest pain developing during VOC who now has SpO2 82% on room air, RR 32, and new bilateral pulmonary infiltrates", "Thalassemia patient asking about reproductive options and genetic counseling", "MDS patient with stable hemoglobin 9.0 on erythropoietin"], a: 1, r: "SpO2 82% + bilateral infiltrates + chest pain during VOC = SEVERE acute chest syndrome progressing to acute respiratory failure. ACS is the #1 cause of death in SCD. IMMEDIATE: high-flow O2 (goal SpO2 >95%), urgent exchange transfusion (target HbS <30%), blood cultures + broad-spectrum antibiotics, and ICU transfer. Consider intubation if respiratory failure worsens.", s: "Hematology" },
  { q: "The nurse receives report on four patients. Which requires FIRST assessment?", o: ["RA patient with mild bilateral wrist swelling — typical finding", "AML patient post-chemotherapy day 12, ANC 0, who now has perioral numbness, muscle cramping, positive Chvostek sign, and QTc prolongation on telemetry", "Thalassemia patient with scheduled transfusion tomorrow", "SCD patient with chronic pain on hydroxyurea with stable Hgb"], a: 1, r: "Perioral numbness + muscle cramping + positive Chvostek sign + prolonged QTc = HYPOcalcemia, likely from tumor lysis syndrome (hyperphosphatemia → calcium-phosphate precipitation → hypocalcemia). QTc prolongation risks torsades de pointes. IMMEDIATE: check calcium, phosphorus, potassium; administer IV calcium gluconate for cardiac protection; continuous cardiac monitoring.", s: "Hematology" },
  { q: "Four patients with SCD need nursing attention. Which patient should be seen FIRST?", o: ["Patient with chronic leg ulcers being managed with wound care", "6-year-old SCD patient whose parent reports child suddenly became very pale, abdomen is distended, child is lethargic, and heart rate is 160", "Adult SCD patient with stable VOC pain managed on PCA at 5/10", "SCD patient requesting refill of folic acid supplement"], a: 1, r: "Sudden pallor + abdominal distension + lethargy + tachycardia in a young SCD child = ACUTE SPLENIC SEQUESTRATION CRISIS. The spleen is rapidly trapping blood, causing hypovolemic shock. This can be FATAL within minutes. IMMEDIATE: two large-bore IVs, rapid NS bolus (20 mL/kg), type and crossmatch for URGENT transfusion, notify physician/surgeon STAT. Spleen may be palpable and rapidly enlarging.", s: "Hematology" },
  { q: "The nurse is prioritizing care for four patients. Which patient should be assessed FIRST?", o: ["OA patient 3 days post-TKR with ROM exercises progressing well", "Pancytopenia patient with newly diagnosed aplastic anemia who is receiving horse ATG (anti-thymocyte globulin) and now develops fever 39.5°C, rigors, urticaria, and joint pain during the infusion", "RA patient on stable methotrexate with monthly lab monitoring", "Thalassemia patient between transfusions with Hgb 9.2"], a: 1, r: "Fever + rigors + urticaria + joint pain during ATG infusion = serum sickness reaction. ATG is a horse protein foreign to the human immune system. Infusion reactions range from mild (fever, rash) to severe (anaphylaxis). IMMEDIATE: slow or stop the infusion, administer IV corticosteroids and antihistamines (usually pre-medicated but may need additional doses). Monitor for anaphylaxis.", s: "Hematology" },
  { q: "Four patients with chronic disease complications need nursing attention. Which finding is MOST concerning?", o: ["T2DM patient with stable diabetic nephropathy on ACE inhibitor", "SCD patient with known pulmonary hypertension who now has increasing dyspnea, pedal edema, JVD, and a new tricuspid regurgitation murmur", "OA patient with well-managed knee pain on topical NSAIDs", "RA patient with stable rheumatoid nodules on biologics"], a: 1, r: "Worsening dyspnea + edema + JVD + new tricuspid regurgitation = right heart failure from progressive pulmonary hypertension. In SCD, chronic intravascular hemolysis releases free hemoglobin that scavenges nitric oxide, causing progressive pulmonary vasculopathy. Pulmonary hypertension affects 6-10% of SCD patients and carries high mortality. Urgent echocardiogram, cardiology/pulmonology consult, and possible right heart catheterization.", s: "Hematology" },
  { q: "The nurse is delegating care for four hematology patients. Which task can be safely delegated to the UAP?", o: ["Assessing a neutropenic patient's oral mucosa for signs of infection", "Teaching a sickle cell patient about hydroxyurea side effects", "Recording strict intake and output on a DKA patient on insulin drip", "Administering IV push morphine for a sickle cell VOC"], a: 2, r: "Recording I&O is within UAP scope — it is a measurement task that does not require clinical judgment. Assessing oral mucosa in neutropenia (requires RN assessment — recognizing subtle infection signs without typical inflammation), teaching about medications (RN scope), and IV push opioid administration (RN scope — requires assessment and monitoring) cannot be delegated.", s: "Hematology" },
  { q: "The nurse is caring for four patients with musculoskeletal conditions. Which patient should be assessed FIRST?", o: ["OA patient asking about joint protection techniques for the kitchen", "RA patient on tocilizumab who has lower abdominal pain, rebound tenderness, and absent bowel sounds — but temperature is only 37.1°C and WBC is 4,200", "Osteoporosis patient with scheduled DEXA scan", "OA patient post-TKR day 5 progressing with PT toward discharge"], a: 1, r: "Abdominal pain + rebound tenderness + absent bowel sounds in a patient on tocilizumab = possible GI perforation. Tocilizumab (IL-6 receptor blocker) MASKS typical infection/inflammation signs — it suppresses fever, CRP, and WBC responses. The normal temperature and WBC are FALSELY reassuring. GI perforation is a known tocilizumab complication. IMMEDIATE surgical evaluation.", s: "Musculoskeletal" },
  { q: "Four patients are being managed in the endocrine clinic. Which patient should be seen FIRST?", o: ["T2DM patient with A1c 7.5% requesting lifestyle counseling", "Addison disease patient who reports stopping fludrocortisone 2 weeks ago because 'it was just for blood pressure' and now has dizziness, salt craving, and K+ 6.1 mEq/L", "Hypothyroid patient with TSH 8.0 on dose adjustment", "T2DM patient with mild neuropathy on duloxetine"], a: 1, r: "Fludrocortisone discontinuation + K+ 6.1 = dangerous hyperkalemia from aldosterone deficiency. Fludrocortisone replaces aldosterone in primary AI — without it, sodium wasting and potassium retention occur. K+ 6.1 risks cardiac arrhythmia. IMMEDIATE: 12-lead ECG, IV calcium gluconate if EKG changes, resume fludrocortisone, and monitor electrolytes. Educate that fludrocortisone is NOT optional.", s: "Endocrine" },
  { q: "Four patients need nursing attention on the medical unit. Which finding requires the MOST urgent response?", o: ["T2DM patient with glucose 200 before dinner", "OA patient reporting 3/10 knee pain while walking with prescribed walker", "Leukemia patient post-transplant day 30 with new CMV reactivation (positive CMV PCR, rising viral load) and persistent fever despite broad-spectrum antibiotics", "RA patient with stable disease activity on combination DMARD therapy"], a: 2, r: "CMV reactivation post-transplant + persistent fever despite antibiotics = opportunistic viral infection in an immunocompromised host. CMV can cause pneumonitis, hepatitis, colitis, and retinitis in post-transplant patients. IMMEDIATE: start IV ganciclovir (or valganciclovir), serial CMV PCR monitoring, and assess for end-organ involvement (CT chest, LFTs, ophthalmology for retinitis).", s: "Hematology" },
  { q: "The nurse is evaluating four patients for safe discharge. Which patient is NOT ready for discharge?", o: ["DKA patient: anion gap closed, pH 7.40, eating well, on SQ insulin with good glucose control for 24 hours", "SCD patient: VOC resolved, pain 2/10 on oral medications, baseline hemoglobin, eating/drinking well", "Aplastic anemia patient: ANC 150, Hgb 7.2, platelets 12,000 — lives alone, does not understand when to seek emergency care", "RA patient: stable on methotrexate with scheduled follow-up in 2 weeks"], a: 2, r: "This patient is NOT safe for discharge: (1) ANC 150 = severely neutropenic (high infection risk); (2) Hgb 7.2 = symptomatic anemia risk; (3) platelets 12,000 = spontaneous bleeding risk; (4) lives alone with poor understanding of emergency signs. Discharge requires: adequate education, reliable caregiver, clear return precautions, close outpatient follow-up, and counts that are either recovering or at safe levels.", s: "Hematology" },
  { q: "Four patients with endocrine conditions are being managed. Which patient situation is MOST urgent?", o: ["T2DM patient with well-controlled glucose on oral medications", "Patient with pheochromocytoma scheduled for surgery in 2 days who has not yet received alpha-blocker therapy and is currently hypertensive at 210/130 with headache", "Hypothyroid patient on dose-adjusted levothyroxine", "Cushing syndrome patient awaiting CT scan results"], a: 1, r: "Pheochromocytoma patient with severe uncontrolled hypertension (210/130) + headache WITHOUT alpha-blockade = hypertensive crisis from unopposed catecholamine surge. Alpha-blockade (phenoxybenzamine) must be started 10-14 days BEFORE surgery to allow volume expansion and BP control. Surgery without adequate alpha-blockade risks intraoperative lethal hypertensive crisis. Start alpha-blocker IMMEDIATELY.", s: "Endocrine" },
  { q: "The nurse is reviewing four patients' lab results. Which result warrants the MOST urgent action?", o: ["T2DM patient: fasting glucose 135 (above target but stable)", "Leukemia patient post-chemotherapy: WBC 800, ANC 200 — expected nadir, afebrile", "SCD patient: Hgb 6.2 (baseline 7.5) with new reticulocyte count of 0.1%, temperature 38°C, and diffuse rash", "Thalassemia patient: ferritin 900 on chelation (trending down from 1,200)"], a: 2, r: "Hgb below baseline + reticulocyte count near zero (0.1%) + fever + rash = APLASTIC CRISIS from parvovirus B19. Parvovirus destroys erythroid precursors, halting RBC production. With SCD's shortened RBC lifespan (10-20 days), hemoglobin drops rapidly. The patient needs IMMEDIATE RBC transfusion, isolation (parvovirus is contagious to pregnant women and immunocompromised), and close monitoring.", s: "Hematology" },
  { q: "The nurse receives handoff report on four patients. Which patient requires IMMEDIATE assessment?", o: ["RA patient with mild bilateral hand swelling — expected disease finding", "Pancytopenia patient with ANC 300 who was found unresponsive by family — blood glucose is 28 mg/dL, and they recently started trimethoprim-sulfamethoxazole", "OA patient with scheduled knee injection appointment", "Thalassemia patient with stable ferritin on chelation"], a: 1, r: "Unresponsive + glucose 28 mg/dL = severe hypoglycemia-induced loss of consciousness. TMP-SMX can potentiate hypoglycemia in patients on sulfonylureas by competing for protein binding. However, in any patient found unresponsive with glucose 28, IMMEDIATE treatment is required regardless of cause: IV D50 25-50mL push, and secondary assessment after glucose normalizes. Investigate the cause (medications, sepsis, hepatic failure).", s: "Hematology" },
  { q: "Four patients with endocrine conditions are being managed in the ICU. Which patient needs IMMEDIATE nursing intervention?", o: ["DKA patient with glucose 250, anion gap 18, pH 7.28 — on insulin drip with appropriate electrolyte replacement", "T2DM patient with HHS, glucose down to 300 from 900, improving mental status on fluids and insulin", "Thyroid storm patient on propranolol, PTU, hydrocortisone, and SSKI — heart rate now 108 (was 170)", "Adrenal crisis patient who received stress-dose hydrocortisone but now has glucose 32, is diaphoretic, and has a new seizure"], a: 3, r: "Adrenal crisis + glucose 32 + seizure = severe hypoglycemia-induced seizure. Cortisol is essential for gluconeogenesis; despite hydrocortisone replacement, this patient has developed critical hypoglycemia. IMMEDIATE: IV D50 push (25-50mL), protect airway during seizure, recheck glucose q15min, and reassess hydrocortisone dosing. The hypoglycemia may indicate insufficient cortisol replacement or additional cause.", s: "Endocrine" },
  { q: "Four patients need the nurse's attention. Which patient should be assessed FIRST?", o: ["T2DM patient with stable neuropathy on gabapentin asking about dose adjustment", "Osteoporosis patient who fell at home 2 hours ago and now has severe mid-back pain with point tenderness over T12 — she is on chronic prednisone for RA", "OA patient with bilateral knee pain managed with topical NSAIDs", "Hypothyroid patient on stable levothyroxine with next TSH check due in 4 weeks"], a: 1, r: "Fall + severe mid-back pain + T12 tenderness + chronic glucocorticoid use + osteoporosis = probable vertebral compression fracture. Chronic prednisone causes significant bone loss (GIO). IMMEDIATE assessment: neurological exam (rule out cord compression — check lower extremity strength, sensation, reflexes, bladder function), imaging (X-ray/MRI), pain management, and consider vertebroplasty if conservative management fails.", s: "Musculoskeletal" },
  { q: "The nurse is caring for four patients on insulin therapy. Which finding requires the MOST immediate action?", o: ["T2DM patient with glucose 180 before dinner — will receive correction dose", "T1DM patient who reports vision changes, headache, and nausea 6 hours into DKA treatment — glucose has dropped from 600 to 200 in those 6 hours", "T2DM patient with glucose 250 fasting — provider notified, awaiting new orders", "T1DM patient with glucose 110 eating lunch appropriately"], a: 1, r: "Glucose drop of 400 in 6 hours (approximately 67 mg/dL/hr — target is 50-75/hr but combined with vision changes, headache, and nausea) = WARNING SIGNS of cerebral edema. While the rate is within range, the neurological symptoms are the key concern. IMMEDIATELY: reduce insulin drip rate, add D5 to IV fluids, neurological assessment, and prepare for mannitol or hypertonic saline if symptoms worsen.", s: "Endocrine" },
  { q: "Four patients with thyroid conditions are being managed. Which patient situation requires the MOST immediate attention?", o: ["Hypothyroid patient with constipation being managed with dietary fiber", "Graves disease patient 2 weeks post-RAI who now has worsening thyrotoxicosis symptoms — heart rate 140, temperature 38.9°C, agitation, and tremor", "Thyroid nodule patient awaiting biopsy scheduled for next week", "Post-thyroidectomy patient 6 months out on stable levothyroxine"], a: 1, r: "Worsening thyrotoxicosis post-RAI = radiation thyroiditis causing release of stored thyroid hormones. This can precipitate thyroid storm. RAI destroys thyroid cells, which release preformed T3/T4 as they die — transiently worsening hyperthyroidism in the first 2-4 weeks. IMMEDIATE: assess for thyroid storm (Burch-Wartofsky score), beta-blocker, cooling measures, and consider antithyroid drugs.", s: "Endocrine" },
  { q: "Four patients need nursing attention on the endocrine unit. Which patient should be assessed FIRST?", o: ["SIADH patient with sodium 128 on fluid restriction — sodium slowly improving", "T2DM patient on new GLP-1 RA reporting mild nausea", "Diabetes insipidus patient post-transsphenoidal surgery with urine output 800mL in the last hour, specific gravity 1.001, and serum sodium rising to 152", "Cushing syndrome patient awaiting diagnostic testing"], a: 2, r: "Massive urine output (800mL/hr) + dilute urine (SG 1.001) + hypernatremia (Na 152) post-pituitary surgery = central diabetes insipidus from posterior pituitary damage. ADH deficiency → uncontrolled water loss. IMMEDIATE: administer desmopressin (DDAVP), replace fluid losses (D5W or hypotonic saline), monitor sodium q2-4h (correct slowly to prevent cerebral edema), and strict I&O.", s: "Endocrine" },
  { q: "The nurse is prioritizing four patients. Which patient requires FIRST assessment?", o: ["Sickle cell patient with stable chronic pain on oral medications", "Leukemia patient post-chemotherapy day 10 who develops ecchymoses over trunk, gum bleeding, and petechiae — platelet count reported as 5,000", "Thalassemia patient receiving a routine blood transfusion — vital signs stable", "Pancytopenia patient with stable counts being observed"], a: 1, r: "Platelet count 5,000 + active bleeding (ecchymoses, gum bleeding, petechiae) = critical thrombocytopenia with hemorrhagic manifestations. At this platelet level, spontaneous intracranial hemorrhage risk is significant. IMMEDIATE: platelet transfusion (apheresis unit), apply gentle pressure to gum bleeding, assess for signs of intracranial hemorrhage (headache, altered LOC, neurological changes), and fall precautions.", s: "Hematology" },
  { q: "Four patients with chronic conditions need assessment. Which finding is MOST concerning?", o: ["RA patient with stable bilateral MCP joint swelling on DMARDs", "Osteoporosis patient on alendronate for 8 years who reports new onset of dull thigh pain that worsens with weight-bearing — no recent trauma", "OA patient with moderate knee crepitus on examination", "T2DM patient with stable glucose control on metformin"], a: 1, r: "New-onset thigh pain after prolonged bisphosphonate use (8 years) + no trauma = suspected atypical femoral fracture. Long-term bisphosphonates oversuppress bone turnover, leading to brittle bone that develops stress fractures in the femoral shaft (lateral cortex). IMMEDIATE: X-ray of bilateral femurs (often bilateral), orthopedic referral, discontinue bisphosphonate, and consider drug holiday vs alternative agent.", s: "Musculoskeletal" },
  { q: "Four patients in the endocrine clinic need assessment. Which patient should be seen FIRST?", o: ["T2DM patient with HbA1c 7.0% — at target", "Cushing syndrome patient post-bilateral adrenalectomy 3 months ago who reports fatigue, dizziness, nausea, and has not been taking prescribed hydrocortisone for the past week because 'the surgery fixed the problem'", "Hypothyroid patient on stable levothyroxine with next lab check scheduled", "T2DM patient asking about adding a GLP-1 RA to their regimen"], a: 1, r: "Post-bilateral adrenalectomy + not taking hydrocortisone for a week = IMPENDING ADRENAL CRISIS. Bilateral adrenalectomy removes ALL adrenal cortisol production — the patient requires LIFELONG glucocorticoid AND mineralocorticoid replacement. Stopping hydrocortisone is immediately life-threatening. IMMEDIATE: check vitals, give stress-dose hydrocortisone if hypotensive, resume replacement therapy, and educate about the absolute necessity of lifelong steroids.", s: "Endocrine" },
  { q: "The nurse is managing four patients. Which patient needs the MOST urgent intervention?", o: ["RA patient on hydroxychloroquine with scheduled ophthalmology exam next month", "ALL patient on induction chemotherapy with WBC 120,000 at diagnosis who now has sudden headache, confusion, and bilateral papilledema — day 3 of treatment with potassium 6.8 and uric acid 14", "SCD patient with resolved VOC being discharged on hydroxyurea", "T2DM patient with A1c 8.0% — medication adjustment being planned"], a: 1, r: "K+ 6.8 + uric acid 14 + neurological symptoms during leukemia induction = severe tumor lysis syndrome. Rapid tumor cell death releases K+, phosphorus, uric acid → hyperkalemia (cardiac arrhythmia risk at 6.8), hyperuricemia (renal failure), hyperphosphatemia → hypocalcemia. IMMEDIATE: 12-lead ECG, IV calcium gluconate, kayexalate/insulin-glucose for K+, rasburicase for uric acid, aggressive hydration, and ICU transfer.", s: "Hematology" },
  { q: "Four patients need nursing attention. Which assessment takes HIGHEST priority?", o: ["Thalassemia patient on regular chelation with ferritin trending down appropriately", "SCD patient in the ED with VOC who was given meperidine (Demerol) 75mg IM — now having a generalized tonic-clonic seizure", "OA patient with scheduled knee replacement consultation next week", "T2DM patient with glucose 210 awaiting correction dose"], a: 1, r: "Meperidine in SCD + seizure = normeperidine-induced seizure. Meperidine is CONTRAINDICATED in SCD because: (1) its active metabolite normeperidine is renally cleared; (2) SCD patients often have renal impairment; (3) normeperidine accumulates and LOWERS seizure threshold. IMMEDIATE: protect the patient, manage seizure (benzodiazepines), DISCONTINUE meperidine permanently, document adverse reaction, use hydromorphone or morphine instead.", s: "Hematology" },
  { q: "The nurse reviews four patients' medication administration records. Which medication error requires the MOST urgent action?", o: ["Levothyroxine given 20 minutes before breakfast instead of 30 minutes", "Methotrexate 15mg given DAILY instead of WEEKLY to an RA patient — the patient has received 3 consecutive daily doses", "Alendronate taken with orange juice instead of water", "Insulin lispro given 20 minutes before a meal instead of 15 minutes"], a: 1, r: "Methotrexate given DAILY instead of WEEKLY = potentially fatal overdose. Three daily doses = 45mg in 3 days (should have been 15mg total for the week). Methotrexate toxicity: severe pancytopenia, mucositis, hepatotoxicity, renal failure. IMMEDIATE: stop methotrexate, stat CBC, CMP, LFTs, administer leucovorin rescue (folinic acid — bypasses methotrexate's folate blockade), and aggressive IV hydration to enhance renal clearance.", s: "Musculoskeletal" },
  { q: "Four patients with diabetes are being managed. Which patient needs the MOST immediate intervention?", o: ["T2DM patient with glucose 190 before lunch", "T1DM patient who took rapid-acting insulin 30 minutes ago but is now vomiting and unable to eat the meal — glucose is 85 and dropping", "T2DM patient with A1c 7.5% reviewing dietary changes", "T1DM patient with glucose 160 before dinner — will take correction dose"], a: 1, r: "Insulin already given + unable to eat + glucose 85 and dropping = IMMINENT severe hypoglycemia. The rapid-acting insulin will continue to lower glucose for the next 2-4 hours without carbohydrate intake to counterbalance it. IMMEDIATE: administer glucose (juice, glucose gel, IV D50 if needed), anti-emetic to control vomiting, and small frequent carbohydrate intake. Monitor glucose q15min until stable.", s: "Endocrine" },
  { q: "Four patients on the hematology-oncology unit need the nurse's attention. Which patient should be assessed FIRST?", o: ["CML patient on imatinib with complete molecular response", "AML patient post-consolidation chemotherapy, ANC 100, who now has a temperature spike to 39.5°C — blood pressure 88/54, heart rate 122, lactate 4.2", "ALL patient in maintenance on oral 6-MP with stable counts", "MDS patient on azacitidine with expected post-treatment cytopenias"], a: 1, r: "ANC 100 + fever + hypotension + tachycardia + lactate 4.2 = neutropenic SEPTIC SHOCK. This is the highest acuity hematologic emergency. IMMEDIATE (within 30 minutes): blood cultures (2 sets), empiric broad-spectrum antibiotics (cefepime or meropenem + vancomycin if MRSA risk), aggressive IV fluid resuscitation (30mL/kg), vasopressors if fluid-refractory, lactate trending, and ICU transfer.", s: "Hematology" },
  { q: "The nurse is caring for four patients. Which finding requires the MOST immediate nursing action?", o: ["OA patient with knee pain rated 4/10 — tolerable on current regimen", "Thalassemia patient 15 minutes into blood transfusion who develops sudden back pain, fever 39.5°C, dark red-brown urine, and reports 'feeling of impending doom'", "RA patient with morning stiffness lasting 45 minutes", "T2DM patient with glucose 165 before bedtime"], a: 1, r: "Sudden back pain + fever + dark urine + 'impending doom' during transfusion = ACUTE HEMOLYTIC TRANSFUSION REACTION from ABO incompatibility. IMMEDIATELY: (1) STOP the transfusion; (2) disconnect blood tubing (save the bag); (3) maintain IV access with NS through new tubing; (4) notify blood bank and provider; (5) send blood bank specimens; (6) aggressive IV fluids to maintain renal perfusion; (7) monitor for DIC and renal failure.", s: "Hematology" },
  { q: "Four patients with musculoskeletal conditions need assessment. Which patient situation is MOST concerning?", o: ["OA patient with bilateral knee crepitus on physical exam", "Post-TKR patient day 1 who reports sudden severe calf pain, calf is swollen and warm, with positive Homans sign — they declined pharmacologic DVT prophylaxis", "Osteoporosis patient with T-score -2.5 on bisphosphonate therapy", "RA patient on stable DMARD therapy with controlled disease"], a: 1, r: "Sudden calf pain + swelling + warmth + positive Homans sign post-TKR WITHOUT DVT prophylaxis = suspected DVT. Total joint replacement has the HIGHEST surgical DVT risk (40-60% without prophylaxis). DVT can propagate to PE (potentially fatal). IMMEDIATE: do NOT massage the leg, obtain stat duplex ultrasound, start anticoagulation if confirmed, and monitor for PE symptoms (dyspnea, chest pain, tachycardia).", s: "Musculoskeletal" },
  { q: "The nurse is reviewing four patients' assessment data. Which patient requires the MOST urgent intervention?", o: ["Hypothyroid patient with TSH 7.0 — dose adjustment being planned", "DKA patient on insulin drip whose potassium has dropped to 2.8 mEq/L — insulin drip is still infusing at the current rate", "RA patient with stable disease on methotrexate", "OA patient with well-controlled pain on acetaminophen"], a: 1, r: "K+ 2.8 on active insulin drip = CRITICAL hypokalemia. Insulin drives potassium intracellularly, and the drip is actively worsening the hypokalemia. K+ <3.0 risks fatal cardiac arrhythmia (U waves, QT prolongation, ventricular fibrillation). IMMEDIATE: STOP or REDUCE the insulin drip until K+ >3.3, administer IV potassium replacement (10-20 mEq/hr through central line, cardiac monitor), and recheck K+ in 1-2 hours.", s: "Endocrine" },
  { q: "Four patients need the nurse's attention on the medical-surgical floor. Which patient should be assessed FIRST?", o: ["T2DM patient with stable glucose control being discharged tomorrow", "Osteoporosis patient who received IV zoledronic acid 24 hours ago and now has temperature 38.5°C, myalgias, headache, and fatigue — first infusion", "RA patient with well-controlled disease on biologics", "OA patient post-TKR day 3 progressing well with PT"], a: 1, r: "Fever + myalgias + headache + fatigue 24 hours after first IV zoledronic acid = acute phase reaction (APR). This is common (approximately 30% of patients after first dose) and is caused by activation of γδ T cells. While typically self-limiting (resolves in 24-72 hours), it must be distinguished from infection. Assess: check CBC, blood cultures if concerned, manage symptoms with acetaminophen/NSAIDs. The reaction rarely recurs with subsequent infusions.", s: "Musculoskeletal" },
  { q: "The charge nurse is making assignments for four patients. Which patient should be assigned to the MOST experienced nurse?", o: ["Stable T2DM patient for routine glucose monitoring", "Sickle cell patient admitted for exchange transfusion requiring dual IV access, pre- and post-procedure monitoring, hemoglobin S level tracking, and potential transfusion reactions management", "OA patient post-TKR day 4 preparing for discharge", "Hypothyroid patient on stable levothyroxine dose"], a: 1, r: "Exchange transfusion requires the most experienced nurse: (1) dual large-bore IV access management; (2) coordination with apheresis team; (3) monitoring for transfusion reactions during high-volume blood product administration; (4) hemodynamic monitoring; (5) tracking HbS percentage (goal <30%); (6) electrolyte monitoring (citrate in products can cause hypocalcemia); (7) managing potential hemolytic reactions.", s: "Hematology" },
  { q: "Four patients with bone conditions need nursing attention. Which finding is MOST concerning?", o: ["Osteoporosis patient with stable DEXA results on denosumab", "Osteoporosis patient who stopped denosumab 8 months ago and now presents with acute severe back pain, loss of height, and multiple new vertebral compression fractures on imaging", "OA patient with moderate knee pain managed conservatively", "RA patient with scheduled rheumatology follow-up"], a: 1, r: "Multiple new vertebral fractures after denosumab discontinuation = REBOUND vertebral fractures. Denosumab suppresses RANKL; when stopped, osteoclast activity rebounds dramatically (overshooting baseline), causing rapid bone loss and multiple vertebral fractures. This is why denosumab must NOT be stopped without transitioning to a bisphosphonate. This patient needs urgent pain management, assessment for cord compression, and restart of antiresorptive therapy.", s: "Musculoskeletal" },
  { q: "Four patients are being monitored. Which patient requires the MOST immediate nursing action?", o: ["T2DM patient with glucose 170 on metformin", "Sickle cell patient day 2 of hospitalization for VOC who just had an oxygen saturation alarm — SpO2 92% on room air, reports new bilateral chest pain worse with inspiration, temperature 38.4°C, and RR 24", "RA patient with stable disease on combination DMARDs", "Thalassemia patient on chelation with ferritin 800 (improving)"], a: 1, r: "New bilateral chest pain + dropping SpO2 + fever + tachypnea during VOC = ACUTE CHEST SYNDROME developing. ACS is the #1 cause of death in SCD and often develops 2-3 days into a VOC hospitalization. IMMEDIATE: supplemental oxygen (target SpO2 >95%), blood cultures, broad-spectrum antibiotics + macrolide, simple or exchange transfusion, incentive spirometry, and consider ICU transfer if worsening.", s: "Hematology" },
  { q: "The nurse is evaluating four patients for priority assessment. Which patient should be seen FIRST?", o: ["Cushing syndrome patient with glucose 200 on insulin — expected finding", "Patient on chronic prednisone 40mg daily for RA who is scheduled for emergency appendectomy in 2 hours — no stress-dose steroid order exists", "Hypothyroid patient with TSH 6.8 on dose-adjusted levothyroxine", "T2DM patient with A1c 7.8% being counseled on lifestyle modifications"], a: 1, r: "Chronic high-dose prednisone patient going to surgery WITHOUT stress-dose steroid order = risk of intraoperative adrenal crisis. Chronic exogenous steroids suppress the HPA axis — the adrenals CANNOT mount a cortisol response to surgical stress. IMMEDIATE: notify the surgeon and anesthesiologist, obtain order for IV hydrocortisone 100mg prior to induction and q8h for 24-48 hours post-op.", s: "Endocrine" },
  { q: "Four patients with hematologic conditions need attention. Which patient should be assessed FIRST?", o: ["Thalassemia patient between transfusions with stable Hgb 8.5", "Leukemia patient 4 days post-intrathecal methotrexate who reports severe headache, neck stiffness, photophobia, and temperature 38.8°C", "SCD patient with chronic pain on oral opioids requesting refill", "MDS patient with stable cytopenias on supportive care"], a: 1, r: "Headache + neck stiffness + photophobia + fever post-intrathecal chemotherapy = either bacterial meningitis (from the LP procedure) or chemical meningitis (from the methotrexate). Both require urgent evaluation because bacterial meningitis is rapidly fatal if untreated. IMMEDIATE: lumbar puncture with CSF analysis (cell count, gram stain, culture, protein, glucose), empiric IV antibiotics pending results, and blood cultures.", s: "Hematology" },
  { q: "The nurse is triaging four patients in the ED. Which patient needs the MOST immediate intervention?", o: ["T2DM patient with glucose 280 requesting medication refill", "Osteoporosis patient with chronic thoracic kyphosis and stable back pain", "RA patient reporting a new flare with bilateral wrist swelling", "SCD patient with sudden onset severe headache, left arm weakness, and slurred speech — CT shows acute right MCA ischemic stroke"], a: 3, r: "Acute stroke in SCD = neurological EMERGENCY. SCD patients have high stroke risk from progressive cerebral vasculopathy. IMMEDIATE: (1) emergent exchange transfusion (target HbS <30%) — this is the primary SCD-specific treatment; (2) standard stroke protocol (CT, evaluate for tPA if within window); (3) neurology consult; (4) continuous neuro monitoring. SCD patients with one stroke have 60-90% recurrence risk without chronic transfusion.", s: "Hematology" },
  { q: "Four patients with musculoskeletal conditions need the nurse's attention. Which situation requires the MOST urgent response?", o: ["RA patient with mild bilateral hand stiffness on DMARD therapy", "Post-THR patient day 1 who reports acute dyspnea, pleuritic chest pain, SpO2 88%, heart rate 118, and blood-tinged sputum", "OA patient with moderate knee pain requesting ice pack", "Osteoporosis patient asking about exercise recommendations"], a: 1, r: "Acute dyspnea + pleuritic chest pain + hypoxia + tachycardia + hemoptysis post-THR = PULMONARY EMBOLISM. THA has the highest PE risk of any surgery. This is a life-threatening emergency. IMMEDIATE: high-flow oxygen, stat CT pulmonary angiogram (or bedside echocardiogram if hemodynamically unstable), start anticoagulation (heparin drip), and prepare for possible thrombolysis or embolectomy if massive PE with hemodynamic instability.", s: "Musculoskeletal" },
  { q: "The nurse is making patient assignments. Which patient requires the MOST experienced nurse?", o: ["Stable OA patient on postoperative day 4 being prepared for discharge", "DKA patient transitioning from IV insulin drip to SQ insulin — anion gap just closed, needs overlap dosing, mealtime coverage, discharge teaching on insulin self-administration, and glucose monitoring", "Hypothyroid patient on stable levothyroxine", "RA patient on stable DMARDs with controlled disease activity"], a: 1, r: "DKA transition is a critical period requiring an experienced nurse: (1) overlap SQ long-acting insulin 2-4 hours before stopping drip (timing error → recurrent DKA); (2) mealtime rapid-acting insulin initiation; (3) potassium monitoring during transition; (4) comprehensive diabetes education (insulin technique, hypoglycemia recognition, sick-day rules, carb counting); (5) discharge planning with follow-up.", s: "Endocrine" },
  { q: "Four patients need the nurse's attention. Which patient should be assessed FIRST?", o: ["T2DM patient with stable glucose on oral medications", "RA patient with bilateral MCP swelling — chronic finding on stable DMARDs", "Aplastic anemia patient post-stem cell transplant day 18 who has a new diffuse maculopapular rash over face, trunk, and palms with simultaneous elevation of bilirubin to 4.2 and watery diarrhea (1L in 8 hours)", "Thalassemia patient with scheduled transfusion appointment"], a: 2, r: "New rash (face/trunk/palms) + elevated bilirubin + profuse diarrhea post-transplant = ACUTE GRAFT-VERSUS-HOST DISEASE affecting skin, liver, and GI tract simultaneously (multiorgan involvement = higher grade/severity). IMMEDIATE: notify transplant team, skin biopsy for confirmation, intensify immunosuppression (high-dose corticosteroids), fluid and electrolyte replacement for diarrhea losses, and monitor for GI bleeding.", s: "Hematology" },
  { q: "Four patients are being managed. Which finding requires the MOST urgent nursing action?", o: ["OA patient with bilateral knee pain managed with exercise and weight loss", "T1DM patient using continuous glucose monitor (CGM) showing glucose 50 with rapid downward trend arrow — patient is alone, sleepy, and has a history of hypoglycemia unawareness", "Hypothyroid patient with TSH slightly elevated on current levothyroxine dose", "RA patient with mild morning stiffness resolving within 30 minutes"], a: 1, r: "CGM showing glucose 50 + rapid downward arrow + hypoglycemia unawareness + sleepiness + alone = IMMINENT severe hypoglycemia. The downward trend means glucose is still falling. Hypoglycemia unawareness means the patient lacks autonomic warning symptoms (tremor, diaphoresis). IMMEDIATE: administer fast-acting glucose (15g), stay with the patient, have glucagon ready, recheck in 15 minutes. This patient needs CGM alarm settings reviewed and hypoglycemia unawareness protocol.", s: "Endocrine" },
  { q: "The nurse is reviewing discharge plans for four patients. Which plan needs IMMEDIATE revision?", o: ["DKA patient discharged with insulin supplies, glucometer, and follow-up in 1 week", "SCD patient discharged on hydroxyurea with monthly CBC monitoring scheduled", "Aplastic anemia patient with ANC 800 discharged home with instructions to 'take ibuprofen as needed for any pain'", "RA patient on methotrexate with folic acid and monthly lab monitoring"], a: 2, r: "Ibuprofen in aplastic anemia with low ANC = DANGEROUS. NSAIDs: (1) impair platelet function (already thrombocytopenic — increased bleeding risk); (2) can cause GI bleeding (especially dangerous with low platelets); (3) may mask fever (a critical sign of infection in neutropenic patients). This discharge instruction must be revised to acetaminophen only, with explicit NSAID avoidance education.", s: "Hematology" },
  { q: "Four patients with endocrine conditions are being monitored. Which finding requires the MOST immediate intervention?", o: ["T2DM patient with fasting glucose 145 — above target but stable", "Patient being treated for thyroid storm who now develops jaundice, RUQ tenderness, and ALT 1,500 — they started PTU 5 days ago", "Cushing syndrome patient with glucose 180 being managed with insulin", "Hypothyroid patient on dose-adjusted levothyroxine with improving symptoms"], a: 1, r: "Jaundice + RUQ tenderness + ALT 1,500 on PTU = PTU-induced hepatotoxicity (fulminant hepatic failure). This is a BLACK BOX WARNING for PTU. Unlike methimazole (which causes cholestatic liver injury), PTU causes hepatocellular necrosis that can be FATAL. IMMEDIATELY stop PTU, check coagulation studies (INR), consult hepatology, and switch to methimazole (if still need antithyroid therapy) or consider alternative treatment.", s: "Endocrine" },
  { q: "Four patients need nursing attention. Which patient should be assessed FIRST?", o: ["T2DM patient with stable nephropathy on ACE inhibitor", "OA patient with moderate knee pain on physical therapy", "Post-TKR patient day 2 with new confusion, SpO2 90%, petechial rash across chest, and temperature 38.2°C — intraoperative course was unremarkable", "RA patient on stable DMARD therapy"], a: 2, r: "Confusion + hypoxia + petechial rash post-TKR = FAT EMBOLISM SYNDROME. Fat globules from the reamed medullary canal enter the venous circulation → lungs (respiratory distress) → cross to systemic circulation (petechiae from small vessel occlusion, CNS changes). Classic triad: respiratory distress, neurological changes, petechial rash (appearing 24-72 hours post-op). IMMEDIATE: high-flow oxygen, supportive care, and ICU transfer.", s: "Musculoskeletal" },
  { q: "The charge nurse is reviewing four patients' plans of care. Which plan requires IMMEDIATE revision?", o: ["T2DM patient with glucose monitoring QAC and HS with sliding scale insulin", "SCD patient with chronic pain on a comprehensive pain management plan including hydroxyurea, folic acid, and scheduled follow-up", "Neutropenic patient (ANC 50) with an order for rectal temperature measurement and a Fleet enema for constipation", "RA patient on weekly methotrexate with folic acid and monthly lab monitoring"], a: 2, r: "Rectal temperature AND rectal enema in a patient with ANC 50 = CONTRAINDICATED and potentially FATAL. Any rectal manipulation in severe neutropenia risks: (1) rectal mucosal trauma → portal of entry for gut flora; (2) perianal abscess; (3) neutropenic enterocolitis from rectal inoculation. In neutropenia: NO rectal temperatures, NO suppositories, NO enemas, NO digital rectal exams. Use oral or tympanic temperature. Use oral laxatives for constipation.", s: "Hematology" },
  { q: "Four patients are being managed in the clinic. Which patient needs IMMEDIATE referral to the ED?", o: ["T2DM patient with A1c 7.8% requesting intensification of therapy", "Osteoporosis patient with new hip pain after a ground-level fall who cannot bear weight — the leg appears shortened and externally rotated", "OA patient with moderate bilateral knee pain requesting NSAIDs", "Hypothyroid patient with cold intolerance on levothyroxine dose adjustment"], a: 1, r: "Fall + inability to bear weight + shortened/externally rotated leg = hip fracture (likely femoral neck or intertrochanteric). Osteoporotic bones fracture with minimal trauma (fragility fracture). Hip fractures have 20-30% one-year mortality in the elderly. IMMEDIATE: immobilize, pain management, ED transfer for imaging and orthopedic consultation. Delay in surgical fixation (>48 hours) increases mortality and complications.", s: "Musculoskeletal" },
  { q: "Four patients with diabetes need the nurse's attention. Which patient assessment finding is MOST urgent?", o: ["T2DM patient with HbA1c 7.5% — above target but improving", "T1DM patient with gastroparesis who took insulin before a meal but is now reporting early satiety after eating only a few bites — glucose is 120 and dropping, and insulin peak is expected in 1 hour", "T2DM patient with stable peripheral neuropathy", "T1DM patient with glucose 200 before a meal — will take correction plus mealtime dose"], a: 1, r: "Gastroparesis + insulin taken + unable to eat adequate carbs + glucose dropping + insulin peak approaching = setup for severe hypoglycemia. Gastroparesis causes unpredictable gastric emptying — the insulin timing no longer matches nutrient absorption. IMMEDIATE: give small amounts of easily digestible carbs (clear juice, glucose tablets), monitor glucose closely, consider dose adjustment strategy (give insulin AFTER eating, use pramlintide cautiously, reduce pre-meal dose).", s: "Endocrine" },
  { q: "The nurse is prioritizing four hematology patients. Which patient needs FIRST assessment?", o: ["SCD patient with well-controlled disease on hydroxyurea with Hgb 9.0", "Leukemia patient post-allogeneic transplant day 45 with new dry cough, progressive dyspnea on exertion, and PFTs showing a declining FEV1 — currently on tacrolimus for GVHD prophylaxis", "Thalassemia patient with ferritin 1,000 on chelation therapy", "MDS patient with stable counts on EPO"], a: 1, r: "Progressive dyspnea + declining FEV1 post-transplant = suspected bronchiolitis obliterans syndrome (BOS), a manifestation of chronic pulmonary GVHD. BOS causes irreversible obstructive airway disease from fibrotic scarring of small airways. IMMEDIATE: chest CT (air trapping, bronchial wall thickening), full PFTs, pulmonology consultation, and discuss intensification of immunosuppression (systemic corticosteroids, FAM protocol). Early detection is critical for best outcomes.", s: "Hematology" },
  { q: "Four patients need the nurse's attention. Which finding requires the MOST immediate action?", o: ["T2DM patient with glucose 200 before dinner", "Thalassemia patient receiving blood transfusion who develops sudden rigors, temperature spike from 37.0°C to 39.8°C, severe back pain, and dark red urine output — transfusion started 20 minutes ago", "RA patient with mild morning stiffness managed with NSAIDs", "OA patient reporting 3/10 knee pain after walking"], a: 1, r: "Sudden rigors + rapid temperature spike + back pain + dark urine during transfusion = ACUTE HEMOLYTIC TRANSFUSION REACTION (most likely ABO incompatibility — most dangerous transfusion reaction). IMMEDIATE: (1) STOP transfusion immediately; (2) disconnect blood, keep IV open with NS through new tubing; (3) notify blood bank; (4) send blood samples for DAT, repeat type/crossmatch; (5) aggressive IV fluids; (6) monitor for DIC, hyperkalemia, and renal failure.", s: "Hematology" },
  { q: "Four patients with endocrine conditions are being monitored. Which patient requires the MOST immediate nursing intervention?", o: ["T2DM patient with glucose 165 before lunch", "Hypothyroid patient with myxedema who has been started on full-dose levothyroxine and now develops chest pain, ST elevation on monitor, and diaphoresis", "Cushing syndrome patient with mild hyperglycemia on insulin", "T2DM patient on metformin with mild GI upset"], a: 1, r: "Chest pain + ST elevation after starting levothyroxine in myxedema = acute MI precipitated by sudden increase in metabolic demand. Myxedema patients have reduced cardiac output and possibly pre-existing CAD. Starting at FULL-DOSE thyroid replacement suddenly increases metabolic demand on a compromised heart. Protocol: start LOW dose (12.5-25mcg) and titrate slowly. This patient needs STAT cardiology consult and ACS protocol.", s: "Endocrine" },
  { q: "The nurse is reviewing four patients' labs. Which combination of findings is MOST concerning?", o: ["T2DM patient: glucose 180, A1c 7.5%", "DKA patient: glucose 300 (decreasing), K+ 3.0, pH 7.25 — insulin drip at 5 units/hour", "Hypothyroid patient: TSH 8.0, free T4 low — adjusting levothyroxine", "T2DM patient: glucose 145, A1c 7.0%"], a: 1, r: "K+ 3.0 on active insulin drip = DANGEROUS. Insulin drives potassium into cells, and K+ 3.0 is already at the lower limit. Continuing insulin at 5 units/hour will drop K+ further → risk of fatal cardiac arrhythmia. Per DKA protocol: if K+ <3.3, HOLD insulin until K+ is replaced to >3.3. IMMEDIATE: reduce or hold insulin drip, administer IV KCl 20-40 mEq/hr (cardiac monitor required), and recheck K+ in 1 hour.", s: "Endocrine" },
  { q: "Four patients need nursing attention. Which patient requires the MOST urgent assessment?", o: ["RA patient with stable swelling on DMARDs", "T1DM patient on insulin pump who reports the insertion site is red, tender, and has purulent drainage — glucose has been running 300-400 for 12 hours despite bolus corrections", "OA patient with crepitus during knee exam", "Thalassemia patient on oral chelation with stable ferritin"], a: 1, r: "Infected pump site + persistent high glucose despite corrections = pump site infection causing insulin malabsorption. The insulin is not being absorbed from the infected subcutaneous tissue. IMMEDIATE: remove the pump site, place a new site in a different location, consider SQ injection to bring glucose down immediately, culture the site drainage, assess for cellulitis/abscess, and check ketones (12 hours of poor insulin delivery may have triggered ketosis).", s: "Endocrine" },
  { q: "Four patients are being managed on the medical-surgical unit. Which patient should be seen FIRST?", o: ["Post-TKR patient day 3 with knee ROM improving to 85 degrees", "Osteoporosis patient with new hip fracture who has been on the floor for 12 hours before being found — now has dark brown urine, creatinine 4.2 (baseline 0.9), CK 25,000, and K+ 6.5", "OA patient with moderate knee pain on acetaminophen", "RA patient with scheduled DMARD infusion this afternoon"], a: 1, r: "Prolonged immobilization on floor + dark urine + CK 25,000 + AKI + hyperkalemia = RHABDOMYOLYSIS with acute kidney injury from crush injury/pressure necrosis. The elderly patient was unable to get up after fracturing the hip. Myoglobin from damaged muscle precipitates in renal tubules causing AKI. K+ 6.5 = cardiac arrhythmia risk. IMMEDIATE: aggressive IV NS, IV calcium gluconate for hyperkalemia, monitor for compartment syndrome, and nephrology consult.", s: "Musculoskeletal" },
  { q: "The nurse is caring for four patients with hematologic conditions. Which patient needs FIRST assessment?", o: ["SCD patient with chronic pain on a stable regimen", "AML patient in induction who develops sudden epistaxis that cannot be controlled with pressure, gum oozing, and oozing from IV sites — labs show PT 22, aPTT 55, fibrinogen 80, D-dimer >20, platelets 25,000", "Thalassemia patient with scheduled transfusion", "MDS patient on azacitidine with expected mild cytopenias"], a: 1, r: "Uncontrollable bleeding from multiple sites + prolonged PT/aPTT + low fibrinogen + massively elevated D-dimer + thrombocytopenia = DISSEMINATED INTRAVASCULAR COAGULATION (DIC). Common in AML, especially APL (M3). IMMEDIATE: treat the underlying cause (continue chemotherapy), cryoprecipitate for fibrinogen <100, FFP for coagulopathy, platelet transfusion, and notify the attending. In APL, start ATRA urgently.", s: "Hematology" },
  { q: "Four patients need the nurse's attention. Which patient requires the MOST immediate intervention?", o: ["T2DM patient with well-controlled glucose on oral medications", "Osteoporosis patient on IV zoledronic acid who developed severe hypocalcemia — calcium 6.8 mEq/L — with tetany, Chvostek sign, and QTc 520ms on monitor", "RA patient with stable disease on biologics", "OA patient with moderate knee pain after physical therapy"], a: 1, r: "Calcium 6.8 + tetany + positive Chvostek + prolonged QTc = SEVERE symptomatic hypocalcemia from bisphosphonate-induced calcium shift into bone (especially if patient was vitamin D deficient before infusion). QTc 520ms risks torsades de pointes. IMMEDIATE: IV calcium gluconate 1-2g slow push (over 10-20 min) with cardiac monitoring, check magnesium (hypomagnesemia worsens hypocalcemia), and replace vitamin D. This is why calcium/vitamin D status should be optimized before bisphosphonate infusion.", s: "Musculoskeletal" },
  { q: "The nurse is triaging four ED patients with bone conditions. Which patient should be seen FIRST?", o: ["Osteoporosis patient with chronic back pain from old compression fracture", "Elderly patient with osteoporosis who fell and has a displaced femoral neck fracture — leg shortened and externally rotated, pedal pulse weak, and foot is cool and pale", "OA patient with knee swelling requesting injection", "Patient asking about DEXA scan scheduling"], a: 1, r: "Displaced femoral neck fracture + weak pedal pulse + cool/pale foot = vascular compromise from fracture displacement. The femoral artery or its branches may be kinked, compressed, or injured by the displaced fracture fragments. This threatens limb viability. IMMEDIATE: immobilize with traction splint, vascular surgery consultation, emergent imaging, and prepare for urgent surgical fixation. Delay risks limb ischemia and potential amputation.", s: "Musculoskeletal" },
  { q: "Four patients are being managed. Which patient situation requires the MOST urgent nursing action?", o: ["SCD patient with stable disease on hydroxyurea with good compliance", "Leukemia patient receiving CAR-T cell therapy who 3 days post-infusion develops fever 40°C, hypotension (78/42), SpO2 85%, confusion, and elevated IL-6 — CRP >300", "RA patient on stable DMARD therapy", "T2DM patient with glucose 185 before dinner"], a: 1, r: "Fever + severe hypotension + hypoxia + confusion 3 days post-CAR-T = SEVERE CYTOKINE RELEASE SYNDROME (CRS Grade 4). Massive T-cell activation releases IL-6, IFN-γ, TNF-α causing systemic inflammatory response → vasodilatory shock → capillary leak → organ failure. IMMEDIATE: tocilizumab 8mg/kg IV (first-line for severe CRS), vasopressors, high-flow O2/mechanical ventilation, dexamethasone if refractory, and ICU management.", s: "Hematology" },
  { q: "The nurse is prioritizing four patients on a medical unit. Which patient should be assessed FIRST?", o: ["Hypothyroid patient with TSH 6.5 on levothyroxine dose adjustment", "T2DM patient on metformin and empagliflozin (SGLT2i) who reports 2 days of nausea, vomiting, abdominal pain, and malaise — glucose is 180 but blood ketones are 4.5 mmol/L", "OA patient with bilateral knee pain rating 4/10 on acetaminophen", "RA patient asking about hydroxychloroquine eye exam scheduling"], a: 1, r: "Nausea + vomiting + abdominal pain + ketones 4.5 with NEAR-NORMAL glucose (180) on SGLT2 inhibitor = EUGLYCEMIC DKA. SGLT2 inhibitors cause glycosuria that keeps glucose deceptively normal while DKA develops from ketogenesis. This is EASILY MISSED because providers expect high glucose with DKA. IMMEDIATE: stop SGLT2i, start IV insulin, IV fluids, check ABG (will show metabolic acidosis), monitor electrolytes, and treat as DKA despite the normal glucose.", s: "Endocrine" },
  { q: "Four patients with chronic conditions need the nurse's attention. Which finding is MOST concerning?", o: ["T2DM patient with A1c 7.2% — slightly above target", "OA patient on chronic high-dose ibuprofen (800mg TID for 3 years) who reports black tarry stools, dizziness, and has hemoglobin of 7.2 (was 13.0 three months ago)", "RA patient with morning stiffness lasting 30 minutes on DMARDs", "Thalassemia patient with ferritin 900 on chelation"], a: 1, r: "Black tarry stools (melena) + Hgb drop from 13 to 7.2 + chronic high-dose NSAID use = UPPER GI BLEEDING from NSAID-induced peptic ulcer. Chronic NSAIDs inhibit COX-1 → reduced prostaglandin-mediated gastric mucosal protection → ulceration → hemorrhage. IMMEDIATE: NPO, two large-bore IVs, type and crossmatch, IV PPI bolus then drip, GI consultation for emergent EGD, and hemodynamic monitoring. STOP all NSAIDs permanently.", s: "Musculoskeletal" },
  { q: "The nurse receives report on four patients. Which patient requires FIRST assessment?", o: ["T2DM patient with stable glucose on insulin therapy", "Pancytopenia patient with aplastic anemia who is 2 hours post-platelet transfusion and now has rigors, fever 39°C, and hypotension — the platelet count has NOT increased from the pre-transfusion level", "OA patient on day 2 post-TKR progressing well", "RA patient with scheduled methotrexate dose today"], a: 1, r: "Post-transfusion rigors + fever + hypotension + failure of platelet increment = either bacterial contamination of platelets (most common cause of fatal transfusion reaction from bacterial products) OR platelet refractoriness from HLA antibodies. IMMEDIATE: blood cultures from patient AND the transfusion bag, broad-spectrum antibiotics, IV fluids for hypotension, and notify the blood bank. Bacterial contamination is more common with platelets because they are stored at room temperature.", s: "Hematology" },
  { q: "Four patients on the endocrine unit need attention. Which patient should be seen FIRST?", o: ["T2DM patient starting a new GLP-1 RA with mild nausea", "SIADH patient with sodium 118 mEq/L who is now having a seizure", "Hypothyroid patient with TSH 10.0 awaiting dose increase", "Cushing syndrome patient with glucose 200 on insulin"], a: 1, r: "Sodium 118 + seizure = severe symptomatic hyponatremia. SIADH causes water retention → dilutional hyponatremia. At Na <120, cerebral edema causes seizures, coma, and brain herniation. IMMEDIATE: (1) protect airway during seizure; (2) administer hypertonic saline (3% NaCl) 100-150mL IV bolus over 10-20 minutes to acutely raise Na by 4-6 mEq/L; (3) recheck Na q2h; (4) correct slowly after initial stabilization (max 8-10 mEq/L in 24h to prevent osmotic demyelination syndrome).", s: "Endocrine" },
  { q: "The nurse is managing four patients. Which patient assessment finding is MOST concerning?", o: ["SCD patient with stable chronic pain on oral analgesics", "RA patient on infliximab who presents with reactivation of hepatitis B — jaundice, RUQ pain, ALT 2,500, and HBV DNA viral load 8 million IU/mL", "OA patient with bilateral Heberden nodes on exam", "Thalassemia patient with Hgb 9.0 between transfusions"], a: 1, r: "HBV reactivation on TNF inhibitor = potentially FATAL fulminant hepatic failure. TNF-α is crucial for controlling HBV replication. TNF inhibition allows massive viral reactivation. ALT 2,500 + high viral load indicates severe hepatic inflammation. IMMEDIATE: stop infliximab, start antiviral therapy (entecavir or tenofovir), hepatology consultation, monitor INR/liver synthetic function for liver failure, and prepare for possible liver transplant evaluation. This is why HBV screening is MANDATORY before starting biologics.", s: "Musculoskeletal" },
  { q: "Four patients need nursing attention. Which patient should be assessed FIRST?", o: ["T2DM patient with fasting glucose 150 on metformin", "Post-thyroidectomy patient day 1 with hoarse voice but able to speak and swallow — voice was normal pre-op", "SCD patient with priapism for 1 hour — applying ice and monitoring", "Leukemia patient with ANC 2,500 on maintenance chemotherapy who reports a painless, non-healing oral ulcer present for 3 weeks"], a: 2, r: "SCD priapism with ICE application = WRONG treatment. Cold causes vasoconstriction and WORSENS sickling. Priapism in SCD is from vaso-occlusion of penile venous outflow. IMMEDIATE: remove ice, apply WARM compresses, hydration, analgesics, and if priapism persists >2-4 hours, urologic consultation for corporal aspiration and phenylephrine irrigation. Delayed treatment risks permanent erectile dysfunction. Correct the harmful intervention immediately.", s: "Hematology" }
];
